struct E6FigureSeries<'a> {
    label: &'a str,
    series: &'a [(f32, f32, f32)],
    color: RGBAColor,
}

fn draw_e6_series_panel<DB: DrawingBackend>(
    area: &DrawingArea<DB, Shift>,
    caption: &str,
    y_desc: &str,
    series_specs: &[E6FigureSeries<'_>],
    y_lo: f32,
    y_hi: f32,
) -> Result<(), Box<dyn Error>>
where
    <DB as DrawingBackend>::ErrorType: 'static,
{
    draw_e6_series_panel_with_x_desc(area, caption, y_desc, "step", series_specs, y_lo, y_hi)
}

fn draw_e6_series_panel_with_x_desc<DB: DrawingBackend>(
    area: &DrawingArea<DB, Shift>,
    caption: &str,
    y_desc: &str,
    x_desc: &str,
    series_specs: &[E6FigureSeries<'_>],
    y_lo: f32,
    y_hi: f32,
) -> Result<(), Box<dyn Error>>
where
    <DB as DrawingBackend>::ErrorType: 'static,
{
    let x_max = series_specs
        .iter()
        .flat_map(|spec| spec.series.iter().map(|(x, _, _)| *x))
        .fold(0.0f32, f32::max)
        .min(E6_FIG_X_MAX)
        .max(1.0);
    let mut chart = ChartBuilder::on(area)
        .caption(caption, ("sans-serif", 64))
        .margin(20)
        .x_label_area_size(90)
        .y_label_area_size(120)
        .build_cartesian_2d(0.0f32..x_max, y_lo..y_hi)?;

    chart
        .configure_mesh()
        .x_desc(x_desc)
        .y_desc(y_desc)
        .x_labels(11)
        .x_label_formatter(&|v| format!("{}", *v as i64))
        .label_style(("sans-serif", 48).into_font())
        .axis_desc_style(("sans-serif", 50).into_font())
        .draw()?;

    for spec in series_specs {
        let label = spec.label;
        let series = spec.series;
        let color = spec.color;
        if series.is_empty() {
            continue;
        }
        let mut band: Vec<(f32, f32)> = Vec::with_capacity(series.len() * 2);
        for (x, mean, ci) in series.iter().copied() {
            band.push((x, (mean + ci).clamp(y_lo, y_hi)));
        }
        for (x, mean, ci) in series.iter().rev().copied() {
            band.push((x, (mean - ci).clamp(y_lo, y_hi)));
        }
        chart.draw_series(std::iter::once(Polygon::new(
            band,
            color.mix(0.20).filled(),
        )))?;

        chart
            .draw_series(LineSeries::new(
                series.iter().map(|(x, mean, _)| (*x, *mean)),
                color,
            ))?
            .label(label)
            .legend(move |(x, y)| PathElement::new(vec![(x, y), (x + 20, y)], color));

        // Dashed extension from last point to x_max
        if let Some(&(last_x, last_mean, _)) = series.last()
            && last_x < x_max - 1.0
        {
            let dash_len = (x_max - last_x) / 80.0;
            let mut segments: Vec<PathElement<(f32, f32)>> = Vec::new();
            let mut cx = last_x;
            while cx < x_max {
                let nx = (cx + dash_len).min(x_max);
                segments.push(PathElement::new(
                    vec![(cx, last_mean), (nx, last_mean)],
                    color.mix(0.5).stroke_width(1),
                ));
                cx = nx + dash_len; // gap
            }
            chart.draw_series(segments)?;
        }
    }

    chart
        .configure_series_labels()
        .position(SeriesLabelPosition::LowerRight)
        .background_style(WHITE.mix(0.85))
        .border_style(BLACK)
        .label_font(("sans-serif", 48).into_font())
        .draw()?;

    chart.draw_series(std::iter::once(Text::new(
        "light: no selection; dark: selection",
        (x_max * 0.03, y_hi - (y_hi - y_lo) * 0.06),
        ("sans-serif", 32).into_font(),
    )))?;
    Ok(())
}

fn draw_e6_factorial_metric_panel<DB: DrawingBackend>(
    area: &DrawingArea<DB, Shift>,
    caption: &str,
    y_desc: &str,
    heredity_nosel: &[f32],
    random_nosel: &[f32],
    heredity_sel: &[f32],
    random_sel: &[f32],
    y_lo: f32,
    y_hi_override: Option<f32>,
    caption_size: u32,
    label_size: u32,
    axis_desc_size: u32,
    y_label_area_size: u32,
) -> Result<(), Box<dyn Error>>
where
    <DB as DrawingBackend>::ErrorType: 'static,
{
    let mean_ci = |values: &[f32]| -> (f32, f32) {
        if values.is_empty() {
            (0.0, 0.0)
        } else {
            (mean_std_scalar(values).0, ci95_half_width(values))
        }
    };
    let (h0_mean, h0_ci) = mean_ci(heredity_nosel);
    let (r0_mean, r0_ci) = mean_ci(random_nosel);
    let (h1_mean, h1_ci) = mean_ci(heredity_sel);
    let (r1_mean, r1_ci) = mean_ci(random_sel);
    let y_hi = y_hi_override.unwrap_or_else(|| {
        [
            h0_mean + h0_ci,
            r0_mean + r0_ci,
            h1_mean + h1_ci,
            r1_mean + r1_ci,
        ]
        .into_iter()
        .fold(y_lo + 1e-6, f32::max)
            * 1.15
    });

    let mut chart = ChartBuilder::on(area)
        .caption(caption, ("sans-serif", caption_size))
        .margin(22)
        .x_label_area_size(90)
        .y_label_area_size(y_label_area_size)
        .build_cartesian_2d(-0.5f32..1.5f32, y_lo..y_hi)?;

    chart
        .configure_mesh()
        .disable_mesh()
        .y_desc(y_desc)
        .x_labels(2)
        .x_label_formatter(&|v| match v.round() as i32 {
            0 => "selection".to_string(),
            1 => "no selection".to_string(),
            _ => String::new(),
        })
        .label_style(("sans-serif", label_size).into_font())
        .axis_desc_style(("sans-serif", axis_desc_size).into_font())
        .draw()?;

    if y_lo < 0.0 && y_hi > 0.0 {
        chart.draw_series(std::iter::once(PathElement::new(
            vec![(-0.5f32, 0.0), (1.5f32, 0.0)],
            BLACK.mix(0.25),
        )))?;
    }

    let bar_specs = [
        (0.0f32 - 0.16, h1_mean, h1_ci, PAL_H.to_rgba()),
        (0.0f32 + 0.16, r1_mean, r1_ci, PAL_R.to_rgba()),
        (1.0f32 - 0.16, h0_mean, h0_ci, PAL_H.mix(0.75)),
        (1.0f32 + 0.16, r0_mean, r0_ci, PAL_R.mix(0.75)),
    ];
    for (center, mean, ci, color) in bar_specs {
        let x0 = center - 0.12;
        let x1 = center + 0.12;
        chart.draw_series(std::iter::once(Rectangle::new(
            [(x0, y_lo), (x1, mean)],
            color.filled(),
        )))?;
        chart.draw_series(std::iter::once(PathElement::new(
            vec![
                (center, (mean - ci).max(y_lo)),
                (center, (mean + ci).min(y_hi)),
            ],
            BLACK.stroke_width(2),
        )))?;
    }

    chart.draw_series(std::iter::once(Text::new(
        "teal: heredity; rose: random",
        (-0.42f32, y_hi * 0.95),
        ("sans-serif", 32).into_font(),
    )))?;

    Ok(())
}

fn draw_e6_heatmap_panel<DB: DrawingBackend>(
    area: &DrawingArea<DB, Shift>,
    heat_counts: &HashMap<(usize, i32), f32>,
) -> Result<(), Box<dyn Error>>
where
    <DB as DrawingBackend>::ErrorType: 'static,
{
    draw_e6_heatmap_panel_with_caption(
        area,
        "B. Heredity + selection pitch heatmap",
        "step",
        heat_counts,
    )
}

fn draw_e6_heatmap_panel_with_caption<DB: DrawingBackend>(
    area: &DrawingArea<DB, Shift>,
    caption: &str,
    x_desc: &str,
    heat_counts: &HashMap<(usize, i32), f32>,
) -> Result<(), Box<dyn Error>>
where
    <DB as DrawingBackend>::ErrorType: 'static,
{
    let (min_range_st, max_range_st) = e6_effective_range_bounds_st();
    let min_range_cents = min_range_st * 100.0;
    let max_range_cents = max_range_st * 100.0;
    let x_max = heat_counts
        .keys()
        .map(|(step, _)| *step as f32)
        .fold(0.0f32, f32::max)
        .min(E6_FIG_X_MAX - E6_SNAPSHOT_INTERVAL as f32)
        + E6_SNAPSHOT_INTERVAL as f32;
    let mut chart = ChartBuilder::on(area)
        .caption(caption, ("sans-serif", 64))
        .margin(20)
        .x_label_area_size(90)
        .y_label_area_size(120)
        .build_cartesian_2d(0.0f32..x_max.max(1.0), min_range_cents..max_range_cents)?;

    chart
        .configure_mesh()
        .x_desc(x_desc)
        .y_desc("cents")
        .x_labels(11)
        .x_label_formatter(&|v| format!("{}", *v as i64))
        .label_style(("sans-serif", 52).into_font())
        .axis_desc_style(("sans-serif", 56).into_font())
        .draw()?;

    let max_count = heat_counts
        .values()
        .copied()
        .fold(0.0f32, f32::max)
        .max(1.0);
    for ((step, bin), count) in heat_counts {
        let x0 = *step as f32;
        let x1 = x0 + E6_SNAPSHOT_INTERVAL as f32;
        let y0 = (min_range_st + *bin as f32 * E6_INTERVAL_BIN_ST) * 100.0;
        let y1 = y0 + E6_INTERVAL_BIN_ST * 100.0;
        let t = (*count / max_count).clamp(0.0, 1.0).sqrt();
        let color = HSLColor(
            (220.0f64 - 220.0f64 * t as f64) / 360.0,
            0.80,
            0.88 - 0.58 * t as f64,
        );
        chart.draw_series(std::iter::once(Rectangle::new(
            [(x0, y0), (x1, y1)],
            ShapeStyle {
                color: color.to_rgba(),
                filled: true,
                stroke_width: 1,
            },
        )))?;
    }

    for &target in &E2_CONSONANT_STEPS {
        let mut y_st = target;
        while y_st > min_range_st {
            y_st -= 12.0;
        }
        while y_st <= max_range_st {
            let y = y_st * 100.0;
            if (min_range_cents..=max_range_cents).contains(&y) {
                chart.draw_series(std::iter::once(PathElement::new(
                    vec![(0.0, y), (x_max.max(1.0), y)],
                    BLACK.mix(0.18),
                )))?;
            }
            y_st += 12.0;
        }
    }

    Ok(())
}

fn draw_e6_integration_endpoint_panel<DB: DrawingBackend>(
    area: &DrawingArea<DB, Shift>,
    h_vals: &[f32],
    hh_vals: &[f32],
    r_vals: &[f32],
    rh_vals: &[f32],
) -> Result<(), Box<dyn Error>>
where
    <DB as DrawingBackend>::ErrorType: 'static,
{
    let mean_ci = |values: &[f32]| -> (f32, f32) {
        if values.is_empty() {
            (0.0, 0.0)
        } else {
            (mean_std_scalar(values).0, ci95_half_width(values))
        }
    };
    let (h_mean, h_ci) = mean_ci(h_vals);
    let (hh_mean, hh_ci) = mean_ci(hh_vals);
    let (r_mean, r_ci) = mean_ci(r_vals);
    let (rh_mean, rh_ci) = mean_ci(rh_vals);
    let y_hi = [
        h_mean + h_ci,
        hh_mean + hh_ci,
        r_mean + r_ci,
        rh_mean + rh_ci,
    ]
    .into_iter()
    .fold(0.0f32, f32::max)
    .max(1e-6)
        * 1.15;

    let mut chart = ChartBuilder::on(area)
        .caption("B. Final C_score", ("sans-serif", 68))
        .margin(18)
        .x_label_area_size(115)
        .y_label_area_size(140)
        .build_cartesian_2d(-0.5f32..1.5f32, 0.0f32..y_hi)?;

    chart
        .configure_mesh()
        .disable_mesh()
        .x_labels(2)
        .x_label_formatter(&|v| match v.round() as i32 {
            0 => "heredity".to_string(),
            1 => "random".to_string(),
            _ => String::new(),
        })
        .y_desc("C_score")
        .label_style(("sans-serif", 46).into_font())
        .axis_desc_style(("sans-serif", 48).into_font())
        .draw()?;

    let bar_specs = [
        (0.0f32 - 0.16, h_mean, h_ci, PAL_H.mix(0.55)),
        (0.0f32 + 0.16, hh_mean, hh_ci, PAL_H.to_rgba()),
        (1.0f32 - 0.16, r_mean, r_ci, PAL_R.mix(0.55)),
        (1.0f32 + 0.16, rh_mean, rh_ci, PAL_R.to_rgba()),
    ];

    for (center, mean, ci, color) in bar_specs {
        let x0 = center - 0.12;
        let x1 = center + 0.12;
        chart.draw_series(std::iter::once(Rectangle::new(
            [(x0, 0.0), (x1, mean)],
            color.filled(),
        )))?;
        chart.draw_series(std::iter::once(PathElement::new(
            vec![
                (center, (mean - ci).max(0.0)),
                (center, (mean + ci).min(y_hi)),
            ],
            BLACK.stroke_width(2),
        )))?;
    }

    chart.draw_series(std::iter::once(Text::new(
        "light: no hill; dark: hill",
        (-0.42f32, y_hi * 0.95),
        ("sans-serif", 34).into_font(),
    )))?;

    Ok(())
}

/// C2: Integration figure — 4 conditions: heredity/random × lw=0.0/1.0
#[allow(clippy::type_complexity)]
fn plot_e6_integration_figure(out_dir: &Path, anchor_hz: f32) -> Result<(), Box<dyn Error>> {
    struct IntegrationCondition {
        label: &'static str,
        condition: E6Condition,
        landscape_weight: f32,
        shuffle_landscape: bool,
        color: RGBColor,
        dashed: bool,
    }

    let conditions = [
        IntegrationCondition {
            label: "heredity",
            condition: E6Condition::Heredity,
            landscape_weight: 0.0,
            shuffle_landscape: false,
            color: RGBColor(58, 106, 120), // PAL_H: deep steel teal
            dashed: false,
        },
        IntegrationCondition {
            label: "heredity+hill",
            condition: E6Condition::Heredity,
            landscape_weight: E6_HILL_LANDSCAPE_WEIGHT,
            shuffle_landscape: false,
            color: RGBColor(76, 153, 76), // green
            dashed: false,
        },
        IntegrationCondition {
            label: "random",
            condition: E6Condition::Random,
            landscape_weight: 0.0,
            shuffle_landscape: false,
            color: RGBColor(204, 121, 50), // orange
            dashed: false,
        },
        IntegrationCondition {
            label: "random+hill",
            condition: E6Condition::Random,
            landscape_weight: E6_HILL_LANDSCAPE_WEIGHT,
            shuffle_landscape: false,
            color: RGBColor(139, 34, 82), // PAL_R: dark rose
            dashed: false,
        },
        IntegrationCondition {
            label: "heredity (shuffled)",
            condition: E6Condition::Heredity,
            landscape_weight: 0.0,
            shuffle_landscape: true,
            color: RGBColor(58, 106, 120), // PAL_H (same as H)
            dashed: true,
        },
        IntegrationCondition {
            label: "heredity+hill (shuffled)",
            condition: E6Condition::Heredity,
            landscape_weight: E6_HILL_LANDSCAPE_WEIGHT,
            shuffle_landscape: true,
            color: RGBColor(76, 153, 76), // green (same as HH)
            dashed: true,
        },
        IntegrationCondition {
            label: "random (shuffled)",
            condition: E6Condition::Random,
            landscape_weight: 0.0,
            shuffle_landscape: true,
            color: RGBColor(204, 121, 50), // orange (same as R)
            dashed: true,
        },
        IntegrationCondition {
            label: "random+hill (shuffled)",
            condition: E6Condition::Random,
            landscape_weight: E6_HILL_LANDSCAPE_WEIGHT,
            shuffle_landscape: true,
            color: RGBColor(139, 34, 82), // PAL_R: dark rose (same as RH)
            dashed: true,
        },
    ];

    let landscape = e3_reference_landscape(anchor_hz);

    // Run all 8 conditions × 20 seeds
    let mut all_series: Vec<(&str, Vec<(f32, f32, f32)>, RGBColor, bool)> = Vec::new();
    let mut csv_data = String::from("condition,step,mean_c_score,ci95\n");
    // Collect seed-level final C_scores for each condition (for interaction test)
    let mut cond_seed_finals: Vec<Vec<f32>> = Vec::new();
    // Collect seed-level final phase coherence R for each condition
    let mut cond_seed_phase: Vec<Vec<f32>> = Vec::new();

    for cond in &conditions {
        // Parallel seed loop
        let seed_results: Vec<(u64, E6RunResult)> = {
            let int_next = AtomicUsize::new(0);
            let int_slots: Mutex<Vec<Option<(u64, E6RunResult)>>> =
                Mutex::new((0..E6_SEEDS.len()).map(|_| None).collect());
            let int_workers = std::thread::available_parallelism()
                .map(|n| n.get())
                .unwrap_or(1)
                .min(E6_SEEDS.len())
                .max(1);
            std::thread::scope(|scope| {
                for _ in 0..int_workers {
                    scope.spawn(|| {
                        loop {
                            let idx = int_next.fetch_add(1, Ordering::Relaxed);
                            if idx >= E6_SEEDS.len() {
                                break;
                            }
                            let seed = E6_SEEDS[idx];
                            let cfg = E6RunConfig {
                                seed,
                                steps_cap: E6_STEPS_CAP,
                                min_deaths: E6_MIN_DEATHS,
                                pop_size: E6_POP_SIZE,
                                first_k: E6_FIRST_K,
                                condition: cond.condition,
                                snapshot_interval: E6_SNAPSHOT_INTERVAL,
                                landscape_weight: cond.landscape_weight,
                                shuffle_landscape: cond.shuffle_landscape,
                                env_partials: None,
                                oracle_azimuth_radius_st: None,
                                oracle_global_anchor_c: false,
                                oracle_freeze_pitch_after_respawn: false,
                                crowding_strength_override: None,
                                adaptation_enabled_override: None,
                                range_oct_override: Some(E2_PAPER_RANGE_OCT),
                                e2_aligned_exact_local_search_radius_st: None,
                                disable_within_life_pitch_movement: false,
                                selection_enabled: true,
                                selection_contextual_mix_weight: 0.0,
                                selection_score_mode: E6SelectionScoreMode::LegacyAnchorContextMix,
                                polyphonic_crowding_weight_override: None,
                                polyphonic_overcapacity_weight_override: None,
                                polyphonic_capacity_radius_cents_override: None,
                                polyphonic_capacity_free_voices_override: None,
                                polyphonic_parent_share_weight_override: None,
                                polyphonic_parent_energy_weight_override: None,
                                juvenile_contextual_tuning_ticks_override: None,
                                juvenile_contextual_settlement_enabled: true,
                                juvenile_cull_enabled: true,
                                record_life_diagnostics: true,
                                survival_score_low_override: None,
                                survival_score_high_override: None,
                                survival_recharge_per_sec_override: None,
                                background_death_rate_per_sec_override: None,
                                respawn_parent_prior_mix_override: None,
                                respawn_same_band_discount_override: None,
                                respawn_octave_discount_override: None,
                                parent_proposal_kind_override: None,
                                parent_proposal_sigma_st_override: None,
                                parent_proposal_unison_notch_gain_override: None,
                                parent_proposal_unison_notch_sigma_st_override: None,
                                parent_proposal_candidate_count_override: None,
                                family_occupancy_strength_override: None,
                                family_nfd_mode: E6FamilyNfdMode::Off,
                                respawn_mode: E6RespawnMode::LegacyFamilyAzimuth,
                                legacy_family_min_spacing_cents: None,
                            };
                            let result = run_e6(&cfg);
                            int_slots.lock().unwrap()[idx] = Some((seed, result));
                        }
                    });
                }
            });
            int_slots
                .into_inner()
                .unwrap()
                .into_iter()
                .map(|o| o.unwrap())
                .collect()
        };

        let mut by_seed: HashMap<u64, Vec<(usize, f32)>> = HashMap::new();
        let mut phase_by_seed: HashMap<u64, Vec<(usize, f32)>> = HashMap::new();
        for (seed, result) in &seed_results {
            for snap in &result.snapshots {
                let point = e6_snapshot_point(&snap.freqs_hz, anchor_hz, &landscape);
                by_seed
                    .entry(*seed)
                    .or_default()
                    .push((snap.step, point.mean_c_score));
                phase_by_seed
                    .entry(*seed)
                    .or_default()
                    .push((snap.step, snap.phase_coherence));
            }
        }

        // Extract final C_score per seed (last snapshot value)
        let mut seed_finals: Vec<f32> = Vec::with_capacity(E6_SEEDS.len());
        let mut seed_phase_finals: Vec<f32> = Vec::with_capacity(E6_SEEDS.len());
        for &seed in &E6_SEEDS {
            if let Some(points) = by_seed.get(&seed) {
                let last_val = points.iter().map(|(_, v)| *v).next_back().unwrap_or(0.0);
                seed_finals.push(last_val);
            } else {
                seed_finals.push(0.0);
            }
            if let Some(points) = phase_by_seed.get(&seed) {
                let last_val = points.iter().map(|(_, v)| *v).next_back().unwrap_or(0.0);
                seed_phase_finals.push(last_val);
            } else {
                seed_phase_finals.push(0.0);
            }
        }
        cond_seed_finals.push(seed_finals);
        cond_seed_phase.push(seed_phase_finals);

        let stats = e6_series_stats(Some(&by_seed), E6_SNAPSHOT_INTERVAL);
        for &(step, mean, ci95) in &stats {
            csv_data.push_str(&format!(
                "{},{},{:.6},{:.6}\n",
                cond.label, step as i64, mean, ci95
            ));
        }
        all_series.push((cond.label, stats, cond.color, cond.dashed));
    }

    // ── Interaction test (full 2×2×2 factorial) ────────────────────────
    // Conditions: 0=H, 1=HH, 2=R, 3=RH, 4=H_s, 5=HH_s, 6=R_s, 7=RH_s
    {
        let n_seeds = E6_SEEDS.len();
        let mean_of = |idx: usize| cond_seed_finals[idx].iter().sum::<f32>() / n_seeds as f32;
        let ci_of = |idx: usize| ci95_half_width(&cond_seed_finals[idx]);

        // Condition means
        let mean_h = mean_of(0);
        let mean_hh = mean_of(1);
        let mean_r = mean_of(2);
        let mean_rh = mean_of(3);
        let mean_h_s = mean_of(4);
        let mean_hh_s = mean_of(5);
        let mean_r_s = mean_of(6);
        let mean_rh_s = mean_of(7);

        // Real-terrain interaction contrast: HH - H - RH + R
        let contrasts: Vec<f32> = cond_seed_finals[0]
            .iter()
            .zip(&cond_seed_finals[1])
            .zip(cond_seed_finals[2].iter().zip(&cond_seed_finals[3]))
            .map(|((&h, &hh), (&r, &rh))| hh - h - rh + r)
            .collect();
        let mean_contrast = contrasts.iter().copied().sum::<f32>() / n_seeds as f32;
        let ci = ci95_half_width(&contrasts);
        let (p_val, method) = permutation_pvalue_one_sample(&contrasts, 100_000, 0xBEEF);

        // Full-shuffled interaction contrast: HH_s - H_s - RH_s + R_s
        let contrasts_shuf: Vec<f32> = cond_seed_finals[4]
            .iter()
            .zip(&cond_seed_finals[5])
            .zip(cond_seed_finals[6].iter().zip(&cond_seed_finals[7]))
            .map(|((&h_s, &hh_s), (&r_s, &rh_s))| hh_s - h_s - rh_s + r_s)
            .collect();
        let mean_contrast_shuf = contrasts_shuf.iter().copied().sum::<f32>() / n_seeds as f32;
        let ci_shuf = ci95_half_width(&contrasts_shuf);
        let (p_val_shuf, _method_shuf) =
            permutation_pvalue_one_sample(&contrasts_shuf, 100_000, 0xBEEF ^ 0x5E6F);

        // H vs H_s and R vs R_s: empirical check that metabolism-only terrain effect is small
        let (h_diff, r_diff): (Vec<f32>, Vec<f32>) = cond_seed_finals[0]
            .iter()
            .zip(&cond_seed_finals[4])
            .zip(cond_seed_finals[2].iter().zip(&cond_seed_finals[6]))
            .map(|((&h, &h_s), (&r, &r_s))| (h - h_s, r - r_s))
            .unzip();
        let mean_h_diff = h_diff.iter().copied().sum::<f32>() / n_seeds as f32;
        let ci_h_diff = ci95_half_width(&h_diff);
        let (p_h_diff, _) = permutation_pvalue_one_sample(&h_diff, 100_000, 0xBEEF ^ 0xA1D1);
        let mean_r_diff = r_diff.iter().copied().sum::<f32>() / n_seeds as f32;
        let ci_r_diff = ci95_half_width(&r_diff);
        let (p_r_diff, _) = permutation_pvalue_one_sample(&r_diff, 100_000, 0xBEEF ^ 0x1D2D);

        let report = format!(
            "Interaction test (sign-flip permutation, {})\n\
             ================================================\n\
             Condition means (final C_score):\n\
             heredity (H):      {:.4}\n\
             heredity+hill (HH): {:.4}\n\
             random (R):         {:.4}\n\
             random+hill (RH):   {:.4}\n\
             \n\
             Interaction contrast: HH - H - RH + R\n\
             mean = {:.4}, 95% CI = [{:.4}, {:.4}]\n\
             p = {:.6} ({})\n\
             n_seeds = {}\n",
            method,
            mean_h,
            mean_hh,
            mean_r,
            mean_rh,
            mean_contrast,
            mean_contrast - ci,
            mean_contrast + ci,
            p_val,
            method,
            n_seeds,
        );
        eprintln!("{}", report);
        write_with_log(out_dir.join("paper_e6_interaction_test.txt"), report)?;

        // Full factorial terrain control report
        let terrain_report = format!(
            "Integration Terrain Control — Full 2×2×2 Factorial\n\
             ===================================================\n\
             Condition                   Mean C_score (final)  95% CI half\n\
             H  (real terrain)           {:.4}                ± {:.4}\n\
             H  (shuffled)               {:.4}                ± {:.4}\n\
             HH (real terrain)           {:.4}                ± {:.4}\n\
             HH (shuffled)               {:.4}                ± {:.4}\n\
             R  (real terrain)           {:.4}                ± {:.4}\n\
             R  (shuffled)               {:.4}                ± {:.4}\n\
             RH (real terrain)           {:.4}                ± {:.4}\n\
             RH (shuffled)               {:.4}                ± {:.4}\n\
             \n\
             Interaction contrast (real):     {:.4} [{:.4}, {:.4}], p = {:.6}\n\
             Interaction contrast (shuffled): {:.4} [{:.4}, {:.4}], p = {:.6}\n\
             \n\
             Metabolism-only terrain effect (no hill-climbing):\n\
             H − H_s:  {:.4} [{:.4}, {:.4}], p = {:.4}\n\
             R − R_s:  {:.4} [{:.4}, {:.4}], p = {:.4}\n\
             \n\
             n_seeds = {}\n",
            mean_h,
            ci_of(0),
            mean_h_s,
            ci_of(4),
            mean_hh,
            ci_of(1),
            mean_hh_s,
            ci_of(5),
            mean_r,
            ci_of(2),
            mean_r_s,
            ci_of(6),
            mean_rh,
            ci_of(3),
            mean_rh_s,
            ci_of(7),
            mean_contrast,
            mean_contrast - ci,
            mean_contrast + ci,
            p_val,
            mean_contrast_shuf,
            mean_contrast_shuf - ci_shuf,
            mean_contrast_shuf + ci_shuf,
            p_val_shuf,
            mean_h_diff,
            mean_h_diff - ci_h_diff,
            mean_h_diff + ci_h_diff,
            p_h_diff,
            mean_r_diff,
            mean_r_diff - ci_r_diff,
            mean_r_diff + ci_r_diff,
            p_r_diff,
            n_seeds,
        );
        eprintln!("{}", terrain_report);
        write_with_log(
            out_dir.join("paper_e6_integration_terrain_test.txt"),
            terrain_report,
        )?;

        // ── Phase coherence report ──────────────────────────────────
        let phase_mean_of = |idx: usize| cond_seed_phase[idx].iter().sum::<f32>() / n_seeds as f32;
        let phase_ci_of = |idx: usize| ci95_half_width(&cond_seed_phase[idx]);
        let cond_labels = ["H", "HH", "R", "RH", "H_s", "HH_s", "R_s", "RH_s"];
        let mut phase_report = String::from(
            "Phase Coherence (Kuramoto R) — Final snapshot\n\
             ==============================================\n\
             Condition                   Mean R    95% CI half\n",
        );
        for (i, label) in cond_labels.iter().enumerate() {
            phase_report.push_str(&format!(
                "{:<28} {:.4}    ± {:.4}\n",
                label,
                phase_mean_of(i),
                phase_ci_of(i),
            ));
        }
        // Phase coherence: HH vs R (does heredity+hill produce higher entrainment?)
        let phase_hh_r: Vec<f32> = cond_seed_phase[1]
            .iter()
            .zip(&cond_seed_phase[3])
            .map(|(&hh, &rh)| hh - rh)
            .collect();
        let phase_hh_r_mean = phase_hh_r.iter().sum::<f32>() / n_seeds as f32;
        let phase_hh_r_ci = ci95_half_width(&phase_hh_r);
        let (phase_hh_r_p, _) = permutation_pvalue_one_sample(&phase_hh_r, 100_000, 0xFA5E_A5A5);
        // Phase: H vs R (heredity-only effect on entrainment)
        let phase_h_r: Vec<f32> = cond_seed_phase[0]
            .iter()
            .zip(&cond_seed_phase[2])
            .map(|(&h, &r)| h - r)
            .collect();
        let phase_h_r_mean = phase_h_r.iter().sum::<f32>() / n_seeds as f32;
        let phase_h_r_ci = ci95_half_width(&phase_h_r);
        let (phase_h_r_p, _) = permutation_pvalue_one_sample(&phase_h_r, 100_000, 0xFA5E_A6A6);
        phase_report.push_str(&format!(
            "\nContrasts:\n\
             HH − RH: {:.4} [{:.4}, {:.4}], p = {:.4}\n\
             H − R:   {:.4} [{:.4}, {:.4}], p = {:.4}\n",
            phase_hh_r_mean,
            phase_hh_r_mean - phase_hh_r_ci,
            phase_hh_r_mean + phase_hh_r_ci,
            phase_hh_r_p,
            phase_h_r_mean,
            phase_h_r_mean - phase_h_r_ci,
            phase_h_r_mean + phase_h_r_ci,
            phase_h_r_p,
        ));
        eprintln!("{}", phase_report);
        write_with_log(out_dir.join("paper_e6_phase_coherence.txt"), phase_report)?;
    }

    // ── Topology generalization sweep (varying env partials) ────────────
    {
        eprintln!("  Running topology generalization sweep for E6 integration...");
        let partials_settings: Vec<(&str, u32)> = vec![
            ("3 partials", 3),
            ("6 partials (default)", 6),
            ("10 partials", 10),
        ];
        let topo_conds = [
            ("H", E6Condition::Heredity, 0.0f32),
            ("HH", E6Condition::Heredity, E6_HILL_LANDSCAPE_WEIGHT),
            ("R", E6Condition::Random, 0.0f32),
            ("RH", E6Condition::Random, E6_HILL_LANDSCAPE_WEIGHT),
        ];
        struct TopologyCondResult {
            topo_idx: usize,
            cond_idx: usize,
            finals: Vec<f32>,
        }
        let topo_jobs: Vec<(usize, &str, u32, usize, &str, E6Condition, f32)> = partials_settings
            .iter()
            .enumerate()
            .flat_map(|(topo_idx, &(tlabel, n_partials))| {
                topo_conds
                    .iter()
                    .enumerate()
                    .map(move |(cond_idx, &(clabel, condition, lw))| {
                        (
                            topo_idx, tlabel, n_partials, cond_idx, clabel, condition, lw,
                        )
                    })
            })
            .collect();
        let topo_results: Vec<TopologyCondResult> = std::thread::scope(|scope| {
            let handles: Vec<_> = topo_jobs
                .iter()
                .map(
                    |&(topo_idx, tlabel, n_partials, cond_idx, clabel, condition, lw)| {
                        scope.spawn(move || {
                            eprintln!("    Topology: {tlabel} / {clabel}");
                            let eval_landscape =
                                e3_reference_landscape_with_partials(anchor_hz, n_partials);
                            let finals: Vec<f32> = E6_SEEDS
                                .iter()
                                .map(|&seed| {
                                    let cfg = E6RunConfig {
                                        seed,
                                        steps_cap: E6_STEPS_CAP,
                                        min_deaths: E6_MIN_DEATHS,
                                        pop_size: E6_POP_SIZE,
                                        first_k: E6_FIRST_K,
                                        condition,
                                        snapshot_interval: E6_SNAPSHOT_INTERVAL,
                                        landscape_weight: lw,
                                        shuffle_landscape: false,
                                        env_partials: Some(n_partials),
                                        oracle_azimuth_radius_st: None,
                                        oracle_global_anchor_c: false,
                                        oracle_freeze_pitch_after_respawn: false,
                                        crowding_strength_override: None,
                                        adaptation_enabled_override: None,
                                        range_oct_override: Some(E2_PAPER_RANGE_OCT),
                                        e2_aligned_exact_local_search_radius_st: None,
                                        disable_within_life_pitch_movement: false,
                                        selection_enabled: true,
                                        selection_contextual_mix_weight: 0.0,
                                        selection_score_mode:
                                            E6SelectionScoreMode::LegacyAnchorContextMix,
                                        polyphonic_crowding_weight_override: None,
                                        polyphonic_overcapacity_weight_override: None,
                                        polyphonic_capacity_radius_cents_override: None,
                                        polyphonic_capacity_free_voices_override: None,
                                        polyphonic_parent_share_weight_override: None,
                                        polyphonic_parent_energy_weight_override: None,
                                        juvenile_contextual_tuning_ticks_override: None,
                                        juvenile_contextual_settlement_enabled: true,
                                        juvenile_cull_enabled: true,
                                        record_life_diagnostics: true,
                                        survival_score_low_override: None,
                                        survival_score_high_override: None,
                                        survival_recharge_per_sec_override: None,
                                        background_death_rate_per_sec_override: None,
                                        respawn_parent_prior_mix_override: None,
                                        respawn_same_band_discount_override: None,
                                        respawn_octave_discount_override: None,
                                        parent_proposal_kind_override: None,
                                        parent_proposal_sigma_st_override: None,
                                        parent_proposal_unison_notch_gain_override: None,
                                        parent_proposal_unison_notch_sigma_st_override: None,
                                        parent_proposal_candidate_count_override: None,
                                        family_occupancy_strength_override: None,
                                        family_nfd_mode: E6FamilyNfdMode::Off,
                                        respawn_mode: E6RespawnMode::LegacyFamilyAzimuth,
                                        legacy_family_min_spacing_cents: None,
                                    };
                                    let result = run_e6(&cfg);
                                    result
                                        .snapshots
                                        .last()
                                        .map(|s| {
                                            let pt = e6_snapshot_point(
                                                &s.freqs_hz,
                                                anchor_hz,
                                                &eval_landscape,
                                            );
                                            pt.mean_c_score
                                        })
                                        .unwrap_or(0.0)
                                })
                                .collect();
                            TopologyCondResult {
                                topo_idx,
                                cond_idx,
                                finals,
                            }
                        })
                    },
                )
                .collect();
            handles
                .into_iter()
                .map(|h| h.join().expect("topology worker thread panicked"))
                .collect()
        });
        let mut topo_finals: Vec<Vec<Vec<f32>>> =
            vec![vec![Vec::new(); topo_conds.len()]; partials_settings.len()];
        for result in topo_results {
            topo_finals[result.topo_idx][result.cond_idx] = result.finals;
        }
        let mut topo_report = String::from(
            "Topology Generalization — E6 Integration\n\
             =========================================\n\
             4 real-terrain conditions (H, HH, R, RH) × 20 seeds per topology\n\
             Varying number of environment partials (changes harmonicity structure)\n\n\
             Topology                        H       HH      R       RH      Contrast  CI95          p\n",
        );
        for (topo_idx, (tlabel, _n_partials)) in partials_settings.iter().enumerate() {
            let tc_finals = &topo_finals[topo_idx];
            let n = E6_SEEDS.len();
            let tm = |i: usize| tc_finals[i].iter().sum::<f32>() / n as f32;
            let contrasts: Vec<f32> = tc_finals[0]
                .iter()
                .zip(&tc_finals[1])
                .zip(tc_finals[2].iter().zip(&tc_finals[3]))
                .map(|((&h, &hh), (&r, &rh))| hh - h - rh + r)
                .collect();
            let tc_mean = contrasts.iter().sum::<f32>() / n as f32;
            let tc_ci = ci95_half_width(&contrasts);
            let (tc_p, _) = permutation_pvalue_one_sample(&contrasts, 100_000, 0xBEEF ^ 0xCEA1);
            topo_report.push_str(&format!(
                "{:<32} {:.3}   {:.3}   {:.3}   {:.3}   {:.3}     [{:.3}, {:.3}]  {:.4}\n",
                tlabel,
                tm(0),
                tm(1),
                tm(2),
                tm(3),
                tc_mean,
                tc_mean - tc_ci,
                tc_mean + tc_ci,
                tc_p,
            ));
        }
        eprintln!("{}", topo_report);
        write_with_log(
            out_dir.join("paper_e6_topology_generalization.txt"),
            topo_report,
        )?;
    }

    write_with_log(
        out_dir.join("paper_e6_integration_timeseries.csv"),
        csv_data,
    )?;

    // Render main figure: real-terrain dynamics + endpoint summary
    let fig_path = out_dir.join("paper_e6_integration_figure.svg");
    let root = bitmap_root(&fig_path, (1600, 630)).into_drawing_area();
    root.fill(&WHITE)?;
    let (left, right) = root.split_horizontally(1140);
    let (left_header, left_plot) = left.split_vertically(120);

    let real_series: Vec<_> = all_series
        .iter()
        .filter(|(_, _, _, dashed)| !*dashed)
        .collect();
    let x_max = real_series
        .iter()
        .flat_map(|(_, s, _, _)| s.iter().map(|(x, _, _)| *x))
        .fold(0.0f32, f32::max)
        .min(E6_FIG_X_MAX)
        .max(1.0);
    let y_lo = 0.0f32;
    let y_hi = real_series
        .iter()
        .flat_map(|(_, s, _, _)| s.iter().map(|(_, mean, ci)| mean + ci))
        .fold(0.0f32, f32::max)
        .max(0.25)
        * 1.08;

    left_header.draw(&Text::new(
        "A. Mean consonance",
        (360, 12),
        ("sans-serif", 70).into_font(),
    ))?;
    let legend_items = [
        ("heredity+hill", RGBColor(76, 153, 76), (60, 82)),
        ("heredity", RGBColor(58, 106, 120), (560, 82)),
        ("random+hill", RGBColor(139, 34, 82), (60, 110)),
        ("random", RGBColor(204, 121, 50), (560, 110)),
    ];
    for (label, color, (x, y)) in legend_items {
        left_header.draw(&PathElement::new(
            vec![(x, y), (x + 42, y)],
            color.stroke_width(4),
        ))?;
        left_header.draw(&Text::new(
            label,
            (x + 52, y - 12),
            ("sans-serif", 36).into_font(),
        ))?;
    }

    let mut chart = ChartBuilder::on(&left_plot)
        .margin(14)
        .margin_bottom(5)
        .x_label_area_size(100)
        .y_label_area_size(115)
        .build_cartesian_2d(0.0f32..x_max, y_lo..y_hi)?;

    chart
        .configure_mesh()
        .x_desc("step")
        .y_desc("C_score")
        .x_labels(11)
        .x_label_formatter(&|v| format!("{}", *v as i64))
        .label_style(("sans-serif", 44).into_font())
        .axis_desc_style(("sans-serif", 46).into_font())
        .draw()?;

    // Draw only the 4 real conditions
    let draw_order: Vec<usize> = vec![1, 0, 3, 2];
    for &idx in &draw_order {
        let (_label, series, color, dashed) = &all_series[idx];
        if series.is_empty() || *dashed {
            continue;
        }
        let mut band: Vec<(f32, f32)> = Vec::with_capacity(series.len() * 2);
        for (x, mean, ci) in series.iter().copied() {
            band.push((x, (mean + ci).clamp(y_lo, y_hi)));
        }
        for (x, mean, ci) in series.iter().rev().copied() {
            band.push((x, (mean - ci).clamp(y_lo, y_hi)));
        }
        chart.draw_series(std::iter::once(Polygon::new(
            band,
            color.mix(0.15).filled(),
        )))?;

        chart.draw_series(LineSeries::new(
            series.iter().map(|(x, mean, _)| (*x, *mean)),
            color.stroke_width(2),
        ))?;
    }

    draw_e6_integration_endpoint_panel(
        &right,
        &cond_seed_finals[0],
        &cond_seed_finals[1],
        &cond_seed_finals[2],
        &cond_seed_finals[3],
    )?;

    root.present()?;
    log_output_path(&fig_path);
    Ok(())
}

fn generate_e6_sampler_debug_plots() -> Result<(), Box<dyn Error>> {
    let out_dir = Path::new(PAPER_PLOTS_BASE_DIR).join("e6");
    create_dir_all(&out_dir)?;

    let seed = E6_SEEDS[0];
    let cfg = E6RunConfig {
        seed,
        steps_cap: E6_STEPS_CAP,
        min_deaths: E6_MIN_DEATHS,
        pop_size: E6_POP_SIZE,
        first_k: E6_FIRST_K,
        condition: E6Condition::Heredity,
        snapshot_interval: E6_SNAPSHOT_INTERVAL,
        landscape_weight: 0.0,
        shuffle_landscape: false,
        env_partials: None,
        oracle_azimuth_radius_st: None,
        oracle_global_anchor_c: false,
        oracle_freeze_pitch_after_respawn: false,
        crowding_strength_override: None,
        adaptation_enabled_override: None,
        range_oct_override: Some(E2_PAPER_RANGE_OCT),
        e2_aligned_exact_local_search_radius_st: None,
        disable_within_life_pitch_movement: false,
        selection_enabled: true,
        selection_contextual_mix_weight: 0.0,
        selection_score_mode: E6SelectionScoreMode::LegacyAnchorContextMix,
        polyphonic_crowding_weight_override: None,
        polyphonic_overcapacity_weight_override: None,
        polyphonic_capacity_radius_cents_override: None,
        polyphonic_capacity_free_voices_override: None,
        polyphonic_parent_share_weight_override: None,
        polyphonic_parent_energy_weight_override: None,
        juvenile_contextual_tuning_ticks_override: None,
        juvenile_contextual_settlement_enabled: true,
        juvenile_cull_enabled: true,
        record_life_diagnostics: true,
        survival_score_low_override: None,
        survival_score_high_override: None,
        survival_recharge_per_sec_override: None,
        background_death_rate_per_sec_override: None,
        respawn_parent_prior_mix_override: None,
        respawn_same_band_discount_override: None,
        respawn_octave_discount_override: None,
        parent_proposal_kind_override: None,
        parent_proposal_sigma_st_override: None,
        parent_proposal_unison_notch_gain_override: None,
        parent_proposal_unison_notch_sigma_st_override: None,
        parent_proposal_candidate_count_override: None,
        family_occupancy_strength_override: None,
        family_nfd_mode: E6FamilyNfdMode::Off,
        respawn_mode: E6RespawnMode::LegacyFamilyAzimuth,
        legacy_family_min_spacing_cents: None,
    };
    let result = run_e6(&cfg);
    let final_snapshot = result
        .snapshots
        .last()
        .ok_or_else(|| io::Error::other("E6 debug run produced no snapshots"))?;

    let mut freqs = final_snapshot.freqs_hz.clone();
    freqs.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    if freqs.is_empty() {
        return Err(io::Error::other("E6 debug run produced no live frequencies").into());
    }

    let parent_freqs = e6_cluster_representative_parent_freqs(&final_snapshot.freqs_hz, 4);

    let scans = parent_freqs
        .iter()
        .map(|&parent_freq_hz| {
            e6_sampler_debug_scan(
                parent_freq_hz,
                &final_snapshot.freqs_hz,
                None,
                E4_BIND_SIGMA_CENTS,
            )
        })
        .collect::<Vec<_>>();

    let png_path = out_dir.join("paper_e6_sampler_debug_seed0_honly.png");
    let root = BitMapBackend::new(&png_path, (1800, 1200)).into_drawing_area();
    root.fill(&WHITE)?;
    let areas = root.split_evenly((2, 2));

    for (area, scan) in areas.into_iter().zip(scans.iter()) {
        let mut chart = ChartBuilder::on(&area)
            .margin(18)
            .x_label_area_size(48)
            .y_label_area_size(58)
            .caption(
                format!(
                    "parent {:.1} st ({:.1} Hz), seed {} H-only final scene",
                    scan.parent_semitones_from_anchor, scan.parent_freq_hz, seed
                ),
                ("sans-serif", 28).into_font(),
            )
            .build_cartesian_2d(-12.5f32..12.5f32, 0.0f32..0.16f32)?;

        chart
            .configure_mesh()
            .x_desc("delta from parent (semitones)")
            .y_desc("PMF")
            .x_labels(9)
            .y_labels(6)
            .label_style(("sans-serif", 20).into_font())
            .axis_desc_style(("sans-serif", 22).into_font())
            .draw()?;

        let plot_stage = |chart: &mut ChartContext<
            '_,
            BitMapBackend<'_>,
            Cartesian2d<RangedCoordf32, RangedCoordf32>,
        >,
                          name: &str,
                          color: RGBColor,
                          data: &[f32]|
         -> Result<(), Box<dyn Error>> {
            let series = scan
                .delta_semitones
                .iter()
                .copied()
                .zip(data.iter().copied())
                .filter(|(x, _)| *x >= -12.5 && *x <= 12.5);
            chart
                .draw_series(LineSeries::new(series, color.stroke_width(3)))?
                .label(name)
                .legend(move |(x, y)| {
                    PathElement::new(vec![(x, y), (x + 20, y)], color.stroke_width(3))
                });
            Ok(())
        };

        plot_stage(&mut chart, "H", RGBColor(70, 70, 70), &scan.harmonicity_pmf)?;
        plot_stage(
            &mut chart,
            "H × local",
            RGBColor(58, 106, 120),
            &scan.harmonicity_local_pmf,
        )?;
        plot_stage(
            &mut chart,
            "× social+tessitura",
            RGBColor(139, 34, 82),
            &scan.final_pmf,
        )?;

        chart.draw_series(std::iter::once(PathElement::new(
            vec![(12.0, 0.0), (12.0, 0.16)],
            BLACK.mix(0.2).stroke_width(1),
        )))?;
        chart
            .configure_series_labels()
            .position(SeriesLabelPosition::UpperRight)
            .background_style(WHITE.mix(0.85))
            .border_style(BLACK.mix(0.25))
            .label_font(("sans-serif", 18).into_font())
            .draw()?;
    }

    root.present()?;
    log_output_path(&png_path);

    let csv_path = out_dir.join("paper_e6_sampler_debug_seed0_honly_peaks.csv");
    let mut csv = String::from("parent_st,parent_hz,stage,rank,delta_st,freq_hz,pmf\n");
    for scan in &scans {
        for (stage_name, data) in [
            ("H", &scan.harmonicity_pmf),
            ("H_local", &scan.harmonicity_local_pmf),
            ("final", &scan.final_pmf),
        ] {
            let mut peaks: Vec<(usize, f32)> = data.iter().copied().enumerate().collect();
            peaks.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
            for (rank, (idx, prob)) in peaks.into_iter().take(10).enumerate() {
                let freq_hz = scan.parent_freq_hz * 2.0f32.powf(scan.delta_semitones[idx] / 12.0);
                csv.push_str(&format!(
                    "{:.3},{:.3},{},{},{:.3},{:.3},{:.8}\n",
                    scan.parent_semitones_from_anchor,
                    scan.parent_freq_hz,
                    stage_name,
                    rank + 1,
                    scan.delta_semitones[idx],
                    freq_hz,
                    prob,
                ));
            }
        }
    }
    write_with_log(csv_path, csv)?;

    let mut tail_csv = String::from(
        "parent_st,parent_hz,stage,mass_abs_gt_12,mass_abs_ge_12,mass_abs_within_12,pmf_neg12,pmf_pos12\n",
    );
    for scan in &scans {
        for (stage_name, data) in [
            ("H", &scan.harmonicity_pmf),
            ("H_local", &scan.harmonicity_local_pmf),
            ("final", &scan.final_pmf),
        ] {
            let mut mass_abs_gt_12 = 0.0f32;
            let mut mass_abs_ge_12 = 0.0f32;
            let mut mass_abs_within_12 = 0.0f32;
            let mut pmf_neg12 = 0.0f32;
            let mut pmf_pos12 = 0.0f32;
            for (&delta_st, &pmf) in scan.delta_semitones.iter().zip(data.iter()) {
                let abs_delta = delta_st.abs();
                if abs_delta > 12.0 + 1e-6 {
                    mass_abs_gt_12 += pmf;
                }
                if abs_delta >= 12.0 - 1e-6 {
                    mass_abs_ge_12 += pmf;
                }
                if abs_delta <= 12.0 + 1e-6 {
                    mass_abs_within_12 += pmf;
                }
                if (delta_st + 12.0).abs() <= 1e-6 {
                    pmf_neg12 += pmf;
                }
                if (delta_st - 12.0).abs() <= 1e-6 {
                    pmf_pos12 += pmf;
                }
            }
            tail_csv.push_str(&format!(
                "{:.3},{:.3},{},{:.8},{:.8},{:.8},{:.8},{:.8}\n",
                scan.parent_semitones_from_anchor,
                scan.parent_freq_hz,
                stage_name,
                mass_abs_gt_12,
                mass_abs_ge_12,
                mass_abs_within_12,
                pmf_neg12,
                pmf_pos12,
            ));
        }
    }
    write_with_log(
        out_dir.join("paper_e6_sampler_debug_seed0_honly_tail.csv"),
        tail_csv,
    )?;

    let respawn_png_path = out_dir.join("paper_e6_respawn_debug_seed0_honly.png");
    render_e6_respawn_debug_plot(&respawn_png_path, &result.respawns)?;
    let mut respawn_csv = String::from(
        "step,dead_agent_id,child_life_id,parent_agent_id,parent_life_id,parent_freq_hz,parent_st,parent_energy,parent_c_level,candidate_count,candidate_energy_mean,candidate_energy_std,candidate_c_level_mean,chosen_selection_prob,offspring_freq_hz,offspring_st,spawn_freq_hz,spawn_st,spawn_c_level,delta_st,parent_family_center_hz,parent_azimuth_st,child_family_center_hz,child_azimuth_st,family_inherited,family_mutated,oracle_applied,oracle_freq_hz,oracle_st,oracle_c_score,oracle_c_level,oracle_delta_st\n",
    );
    for rec in &result.respawns {
        let parent_st = rec
            .parent_freq_hz
            .map(|freq| 12.0 * (freq / E4_ANCHOR_HZ).log2())
            .map(|st| format!("{st:.6}"))
            .unwrap_or_default();
        let parent_freq = rec
            .parent_freq_hz
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let parent_agent_id = rec
            .parent_agent_id
            .map(|v| v.to_string())
            .unwrap_or_default();
        let parent_life_id = rec
            .parent_life_id
            .map(|v| v.to_string())
            .unwrap_or_default();
        let parent_energy = rec
            .parent_energy
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let parent_c_level = rec
            .parent_c_level
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let chosen_selection_prob = rec
            .chosen_selection_prob
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let offspring_st = 12.0 * (rec.offspring_freq_hz / E4_ANCHOR_HZ).log2();
        let spawn_st = 12.0 * (rec.spawn_freq_hz / E4_ANCHOR_HZ).log2();
        let delta_st = rec
            .parent_freq_hz
            .map(|parent_freq| 12.0 * (rec.spawn_freq_hz / parent_freq).log2())
            .map(|st| format!("{st:.6}"))
            .unwrap_or_default();
        let parent_family_center_hz = rec
            .parent_family_center_hz
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let parent_azimuth_st = rec
            .parent_azimuth_st
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let child_family_center_hz = rec
            .child_family_center_hz
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let child_azimuth_st = rec
            .child_azimuth_st
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let family_inherited = rec
            .family_inherited
            .map(|v| if v { "1".to_string() } else { "0".to_string() })
            .unwrap_or_default();
        let family_mutated = rec
            .family_mutated
            .map(|v| if v { "1".to_string() } else { "0".to_string() })
            .unwrap_or_default();
        let oracle_freq = rec
            .oracle_freq_hz
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let oracle_st = rec
            .oracle_freq_hz
            .map(|freq| 12.0 * (freq / E4_ANCHOR_HZ).log2())
            .map(|st| format!("{st:.6}"))
            .unwrap_or_default();
        let oracle_c_score = rec
            .oracle_c_score
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let oracle_c_level = rec
            .oracle_c_level
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        let oracle_delta_st = rec
            .oracle_delta_st
            .map(|v| format!("{v:.6}"))
            .unwrap_or_default();
        respawn_csv.push_str(&format!(
            "{},{},{},{},{},{},{},{},{},{},{:.6},{:.6},{:.6},{},{:.6},{:.6},{:.6},{:.6},{:.6},{},{},{},{},{},{},{},{},{},{},{},{},{}\n",
            rec.step,
            rec.dead_agent_id,
            rec.child_life_id,
            parent_agent_id,
            parent_life_id,
            parent_freq,
            parent_st,
            parent_energy,
            parent_c_level,
            rec.candidate_count,
            rec.candidate_energy_mean,
            rec.candidate_energy_std,
            rec.candidate_c_level_mean,
            chosen_selection_prob,
            rec.offspring_freq_hz,
            offspring_st,
            rec.spawn_freq_hz,
            spawn_st,
            rec.spawn_c_level,
            delta_st,
            parent_family_center_hz,
            parent_azimuth_st,
            child_family_center_hz,
            child_azimuth_st,
            family_inherited,
            family_mutated,
            if rec.oracle_applied { 1 } else { 0 },
            oracle_freq,
            oracle_st,
            oracle_c_score,
            oracle_c_level,
            oracle_delta_st
        ));
    }
    write_with_log(
        out_dir.join("paper_e6_respawn_debug_seed0_honly.csv"),
        respawn_csv,
    )?;
    Ok(())
}

fn e6_cluster_representative_parent_freqs(freqs_hz: &[f32], n_max: usize) -> Vec<f32> {
    let mut semitone_freqs: Vec<(f32, f32)> = freqs_hz
        .iter()
        .copied()
        .filter(|f| f.is_finite() && *f > 0.0)
        .map(|f| (12.0 * (f / E4_ANCHOR_HZ).log2(), f))
        .collect();
    semitone_freqs.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));
    if semitone_freqs.is_empty() {
        return Vec::new();
    }

    let mut clusters: Vec<Vec<(f32, f32)>> = Vec::new();
    let mut current = vec![semitone_freqs[0]];
    for &(st, hz) in semitone_freqs.iter().skip(1) {
        if st - current.last().map(|p| p.0).unwrap_or(st) <= 1.0 {
            current.push((st, hz));
        } else {
            clusters.push(current);
            current = vec![(st, hz)];
        }
    }
    clusters.push(current);
    clusters.sort_by(|a, b| b.len().cmp(&a.len()));

    clusters
        .into_iter()
        .take(n_max)
        .map(|cluster| cluster[cluster.len() / 2].1)
        .collect()
}

fn render_e6_respawn_debug_plot(
    out_path: &Path,
    respawns: &[E6RespawnRecord],
) -> Result<(), Box<dyn Error>> {
    let root = BitMapBackend::new(out_path, (1800, 1000)).into_drawing_area();
    root.fill(&WHITE)?;
    let areas = root.split_evenly((2, 2));

    let parent_st: Vec<f32> = respawns
        .iter()
        .filter_map(|r| {
            r.parent_freq_hz
                .map(|freq| 12.0 * (freq / E4_ANCHOR_HZ).log2())
        })
        .collect();
    let spawn_st: Vec<f32> = respawns
        .iter()
        .map(|r| 12.0 * (r.spawn_freq_hz / E4_ANCHOR_HZ).log2())
        .collect();
    let delta_st: Vec<f32> = respawns
        .iter()
        .filter_map(|r| {
            r.parent_freq_hz
                .map(|parent_freq| 12.0 * (r.spawn_freq_hz / parent_freq).log2())
        })
        .collect();

    {
        let mut chart = ChartBuilder::on(&areas[0])
            .margin(16)
            .caption("Parent semitone histogram", ("sans-serif", 28).into_font())
            .x_label_area_size(40)
            .y_label_area_size(48)
            .build_cartesian_2d(-12.5f32..14.5f32, 0u32..500u32)?;
        chart
            .configure_mesh()
            .x_desc("parent semitones from anchor")
            .y_desc("count")
            .label_style(("sans-serif", 18).into_font())
            .axis_desc_style(("sans-serif", 20).into_font())
            .draw()?;
        let bins = histogram_counts_fixed(&parent_st, -12.5, 14.5, 0.5);
        chart.draw_series(bins.iter().map(|&(center, count)| {
            let x0 = center - 0.25;
            let x1 = center + 0.25;
            Rectangle::new([(x0, 0u32), (x1, count as u32)], PAL_H.mix(0.65).filled())
        }))?;
    }

    {
        let mut chart = ChartBuilder::on(&areas[1])
            .margin(16)
            .caption("Spawned semitone histogram", ("sans-serif", 28).into_font())
            .x_label_area_size(40)
            .y_label_area_size(48)
            .build_cartesian_2d(-12.5f32..14.5f32, 0u32..500u32)?;
        chart
            .configure_mesh()
            .x_desc("spawn semitones from anchor")
            .y_desc("count")
            .label_style(("sans-serif", 18).into_font())
            .axis_desc_style(("sans-serif", 20).into_font())
            .draw()?;
        let bins = histogram_counts_fixed(&spawn_st, -12.5, 14.5, 0.5);
        chart.draw_series(bins.iter().map(|&(center, count)| {
            let x0 = center - 0.25;
            let x1 = center + 0.25;
            Rectangle::new([(x0, 0u32), (x1, count as u32)], PAL_R.mix(0.65).filled())
        }))?;
    }

    {
        let mut chart = ChartBuilder::on(&areas[2])
            .margin(16)
            .caption(
                "Parent vs spawned semitones",
                ("sans-serif", 28).into_font(),
            )
            .x_label_area_size(48)
            .y_label_area_size(48)
            .build_cartesian_2d(-12.5f32..14.5f32, -12.5f32..14.5f32)?;
        chart
            .configure_mesh()
            .x_desc("parent st")
            .y_desc("spawn st")
            .label_style(("sans-serif", 18).into_font())
            .axis_desc_style(("sans-serif", 20).into_font())
            .draw()?;
        chart.draw_series(
            parent_st
                .iter()
                .copied()
                .zip(spawn_st.iter().copied())
                .map(|(x, y)| Circle::new((x, y), 2, RGBColor(80, 80, 80).mix(0.35).filled())),
        )?;
    }

    {
        let mut chart = ChartBuilder::on(&areas[3])
            .margin(16)
            .caption("Spawn delta from parent", ("sans-serif", 28).into_font())
            .x_label_area_size(40)
            .y_label_area_size(48)
            .build_cartesian_2d(-12.5f32..12.5f32, 0u32..400u32)?;
        chart
            .configure_mesh()
            .x_desc("spawn minus parent (st)")
            .y_desc("count")
            .label_style(("sans-serif", 18).into_font())
            .axis_desc_style(("sans-serif", 20).into_font())
            .draw()?;
        let bins = histogram_counts_fixed(&delta_st, -12.5, 12.5, 0.5);
        chart.draw_series(bins.iter().map(|&(center, count)| {
            let x0 = center - 0.25;
            let x1 = center + 0.25;
            Rectangle::new([(x0, 0u32), (x1, count as u32)], PAL_C.mix(0.65).filled())
        }))?;
    }

    root.present()?;
    log_output_path(out_path);
    Ok(())
}

// ── E5 Vitality-Coupled Entrainment: condition enum ──────────────
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
enum E5Condition {
    Vitality,
    Uniform,
    Control,
}

impl E5Condition {
    fn label(self) -> &'static str {
        match self {
            E5Condition::Vitality => "vitality",
            E5Condition::Uniform => "uniform",
            E5Condition::Control => "control",
        }
    }
    fn color(self) -> RGBColor {
        match self {
            E5Condition::Vitality => PAL_E5_VITALITY,
            E5Condition::Uniform => PAL_E5_UNIFORM,
            E5Condition::Control => PAL_E5_CONTROL,
        }
    }
}

/// Coupling multiplier matching `coupling_multiplier_from_mode()` in articulation_core.rs.
/// Maps vitality → multiplicative factor on k_time via `TemporalTimesVitality` logic.
#[inline]
fn e5_coupling_multiplier(vitality: f32, lambda_v: f32, v_floor: f32) -> f32 {
    let denom = (1.0 - v_floor).max(1e-6);
    let g = ((vitality - v_floor) / denom).clamp(0.0, 1.0);
    (lambda_v * g).clamp(0.0, 2.0) // MAX_COUPLING_MULT = 2.0 in main
}

// ── E5 result structs ────────────────────────────────────────────
struct E5VitalityResult {
    /// Per-step group mean PLV
    group_plv_series: Vec<(f32, f32)>,
    /// Per-agent final PLV and consonance
    agent_final: Vec<E5AgentFinal>,
    /// Pearson r(consonance, final PLV) for this run
    pearson_r: f32,
    condition: E5Condition,
    seed: u64,
}

struct E5DeltaSeries {
    label: &'static str,
    color: RGBColor,
    /// (t, mean, ci95)
    series: Vec<(f32, f32, f32)>,
}

struct E5SigmoidFit {
    base: f32,      // y at x → -∞
    amplitude: f32, // y at x → +∞ is base + amplitude
    steepness: f32, // slope of sigmoid (c50 fixed at 0)
}

#[derive(Clone, Copy)]
struct E5AgentFinal {
    consonance: f32,
    plv: f32,
}

// ── E5 pitch selection: stratified by raw C_field ────────────────
/// Scan the landscape over ±1 octave and return N pitches whose
/// raw C_field values are approximately uniformly distributed in [0, scan_max].
/// This ensures the independent variable (C_field) spans the full range.
fn e5_stratified_pitches(
    n: usize,
    landscape: &conchordal::core::landscape::Landscape,
    rng: &mut impl rand::Rng,
) -> (Vec<f32>, Vec<f32>) {
    let log2_lo = E5_ANCHOR_HZ.log2() - 1.0;
    let log2_hi = E5_ANCHOR_HZ.log2() + 1.0;

    // Dense scan: 4000 candidate pitches
    let n_scan = 4000usize;
    let candidates: Vec<(f32, f32)> = (0..n_scan)
        .map(|i| {
            let log2_f = log2_lo + (log2_hi - log2_lo) * (i as f32 / (n_scan - 1) as f32);
            let hz = 2.0f32.powf(log2_f);
            let score = landscape.evaluate_pitch_score(hz);
            (hz, score)
        })
        .collect();

    // Use raw C_field range [scan_min, scan_max] for stratification
    let s_min = candidates.iter().map(|c| c.1).fold(f32::INFINITY, f32::min);
    let s_max = candidates
        .iter()
        .map(|c| c.1)
        .fold(f32::NEG_INFINITY, f32::max);
    let s_range = (s_max - s_min).max(1e-6);

    // Assign each candidate to one of N strata over [s_min, s_max]
    let mut strata: Vec<Vec<(f32, f32)>> = (0..n).map(|_| Vec::new()).collect();
    for &(hz, c) in &candidates {
        let frac = ((c - s_min) / s_range).clamp(0.0, 1.0);
        let bin = ((frac * n as f32) as usize).min(n - 1);
        strata[bin].push((hz, c));
    }

    // Pick one random candidate from each stratum.
    // If a stratum is empty, pick the nearest candidate to that stratum's midpoint.
    let mut pitches = Vec::with_capacity(n);
    let mut consonances = Vec::with_capacity(n);
    for (i, stratum) in strata.iter().enumerate().take(n) {
        let mid_frac = (i as f32 + 0.5) / n as f32;
        let mid_val = s_min + mid_frac * s_range;
        if !stratum.is_empty() {
            let idx = rng.random_range(0..stratum.len());
            let (hz, c) = stratum[idx];
            pitches.push(hz);
            consonances.push(c);
        } else {
            // Fallback: find candidate closest to stratum midpoint (in raw C_field)
            let (hz, c) = *candidates
                .iter()
                .min_by(|a, b| {
                    (a.1 - mid_val)
                        .abs()
                        .partial_cmp(&(b.1 - mid_val).abs())
                        .unwrap()
                })
                .unwrap();
            pitches.push(hz);
            consonances.push(c);
        }
    }
    (pitches, consonances)
}

/// Run E5 simulation with stratified pitches (for Panel B scatter only).
/// Same dynamics as `simulate_e5_vitality` but pitches span the full
/// consonance range so the scatter plot is informative.
fn simulate_e5_stratified(
    seed: u64,
    condition: E5Condition,
    landscape: &conchordal::core::landscape::Landscape,
) -> E5VitalityResult {
    let mut rng = seeded_rng(seed);
    let (_pitches_hz, consonances) = e5_stratified_pitches(E5_N_AGENTS, landscape, &mut rng);

    // --- rest is identical to simulate_e5_vitality ---
    let omegas: Vec<f32> = (0..E5_N_AGENTS)
        .map(|_| {
            let jitter = rng.random_range(-E5_AGENT_JITTER..E5_AGENT_JITTER);
            E5_AGENT_OMEGA_MEAN * (1.0 + jitter)
        })
        .collect();
    let mut phases: Vec<f32> = (0..E5_N_AGENTS)
        .map(|_| rng.random_range(0.0f32..(2.0 * PI)))
        .collect();
    let mut energies: Vec<f32> = vec![E5_E_INIT; E5_N_AGENTS];
    let mut theta_kick = 0.0f32;
    let mut plv_buffers: Vec<SlidingPlv> = (0..E5_N_AGENTS)
        .map(|_| SlidingPlv::new(E5_TIME_PLV_WINDOW_STEPS))
        .collect();
    let mut group_plv_series: Vec<(f32, f32)> = Vec::with_capacity(E5_STEPS);

    for step in 0..E5_STEPS {
        let t = step as f32 * E5_DT;
        // Energy dynamics: dE/dt = R·max(C_field,0) − γ·E
        for i in 0..E5_N_AGENTS {
            let recharge = E5_RECHARGE * consonances[i].max(0.0);
            let de = (recharge - E5_DECAY * energies[i]) * E5_DT;
            energies[i] = (energies[i] + de).clamp(0.0, E5_E_CAP);
        }
        // Vitality
        let vitalities: Vec<f32> = energies
            .iter()
            .map(|&e| (e / E5_E_CAP).clamp(0.0, 1.0).powf(E5_VITALITY_EXPONENT))
            .collect();
        let mean_v: f32 = vitalities.iter().sum::<f32>() / E5_N_AGENTS as f32;
        // Coupling (matches articulation_core coupling_multiplier_from_mode)
        let k_effs: Vec<f32> = match condition {
            E5Condition::Vitality => vitalities
                .iter()
                .map(|&v| E5_K_TIME * e5_coupling_multiplier(v, E5_LAMBDA_V, E5_V_FLOOR))
                .collect(),
            E5Condition::Uniform => {
                let cm = e5_coupling_multiplier(mean_v, E5_LAMBDA_V, E5_V_FLOOR);
                vec![E5_K_TIME * cm; E5_N_AGENTS]
            }
            E5Condition::Control => vec![0.0; E5_N_AGENTS],
        };
        // Phase update (couple each agent to external kick only)
        for i in 0..E5_N_AGENTS {
            phases[i] =
                kuramoto_phase_step(phases[i], omegas[i], theta_kick, k_effs[i], 0.0, E5_DT);
        }
        theta_kick += E5_KICK_OMEGA * E5_DT;
        // PLV tracking
        let mut plv_sum = 0.0f32;
        let mut plv_count = 0usize;
        for i in 0..E5_N_AGENTS {
            let dp = wrap_pm_pi(phases[i] - theta_kick);
            plv_buffers[i].push(dp);
            if plv_buffers[i].is_full() {
                let p = plv_buffers[i].plv();
                if p.is_finite() {
                    plv_sum += p;
                    plv_count += 1;
                }
            }
        }
        let group_plv = if plv_count > 0 {
            plv_sum / plv_count as f32
        } else {
            f32::NAN
        };
        group_plv_series.push((t, group_plv));
    }
    let agent_final: Vec<E5AgentFinal> = (0..E5_N_AGENTS)
        .map(|i| E5AgentFinal {
            consonance: consonances[i],
            plv: if plv_buffers[i].is_full() {
                plv_buffers[i].plv()
            } else {
                f32::NAN
            },
        })
        .collect();
    let pr = pearson_r_e5(&agent_final);
    E5VitalityResult {
        group_plv_series,
        agent_final,
        pearson_r: pr,
        condition,
        seed,
    }
}

// ── E5 simulation ────────────────────────────────────────────────
fn simulate_e5_vitality(
    seed: u64,
    condition: E5Condition,
    landscape: &conchordal::core::landscape::Landscape,
) -> E5VitalityResult {
    let mut rng = seeded_rng(seed);

    // Random pitches within ±1 octave of anchor
    let log2_anchor = E5_ANCHOR_HZ.log2();
    let pitches_hz: Vec<f32> = (0..E5_N_AGENTS)
        .map(|_| {
            let log2_f = rng.random_range((log2_anchor - 1.0)..(log2_anchor + 1.0));
            2.0f32.powf(log2_f)
        })
        .collect();

    // Evaluate consonance (raw C_field — no normalization)
    let consonances: Vec<f32> = pitches_hz
        .iter()
        .map(|&f| landscape.evaluate_pitch_score(f))
        .collect();

    // Intrinsic frequencies with jitter
    let omegas: Vec<f32> = (0..E5_N_AGENTS)
        .map(|_| {
            let jitter = rng.random_range(-E5_AGENT_JITTER..E5_AGENT_JITTER);
            E5_AGENT_OMEGA_MEAN * (1.0 + jitter)
        })
        .collect();

    // Initial phases (random)
    let mut phases: Vec<f32> = (0..E5_N_AGENTS)
        .map(|_| rng.random_range(0.0f32..(2.0 * PI)))
        .collect();

    // Energy state
    let mut energies: Vec<f32> = vec![E5_E_INIT; E5_N_AGENTS];

    // External kick phase
    let mut theta_kick = 0.0f32;

    // PLV tracking
    let mut plv_buffers: Vec<SlidingPlv> = (0..E5_N_AGENTS)
        .map(|_| SlidingPlv::new(E5_TIME_PLV_WINDOW_STEPS))
        .collect();

    let mut group_plv_series: Vec<(f32, f32)> = Vec::with_capacity(E5_STEPS);

    for step in 0..E5_STEPS {
        let t = step as f32 * E5_DT;

        // Energy dynamics: dE/dt = R·max(C_field,0) − γ·E
        for i in 0..E5_N_AGENTS {
            let recharge = E5_RECHARGE * consonances[i].max(0.0);
            let de = (recharge - E5_DECAY * energies[i]) * E5_DT;
            energies[i] = (energies[i] + de).clamp(0.0, E5_E_CAP);
        }

        // Compute vitality per agent
        let vitalities: Vec<f32> = energies
            .iter()
            .map(|&e| (e / E5_E_CAP).clamp(0.0, 1.0).powf(E5_VITALITY_EXPONENT))
            .collect();

        // Compute per-agent coupling (matches articulation_core coupling_multiplier_from_mode)
        let mean_vitality: f32 = vitalities.iter().copied().sum::<f32>() / E5_N_AGENTS as f32;

        // Advance kick phase
        theta_kick += E5_KICK_OMEGA * E5_DT;

        // Phase update per agent
        for i in 0..E5_N_AGENTS {
            let k_eff_i = match condition {
                E5Condition::Vitality => {
                    let cm = e5_coupling_multiplier(vitalities[i], E5_LAMBDA_V, E5_V_FLOOR);
                    E5_K_TIME * cm
                }
                E5Condition::Uniform => {
                    let cm = e5_coupling_multiplier(mean_vitality, E5_LAMBDA_V, E5_V_FLOOR);
                    E5_K_TIME * cm
                }
                E5Condition::Control => 0.0,
            };
            phases[i] = kuramoto_phase_step(phases[i], omegas[i], theta_kick, k_eff_i, 0.0, E5_DT);
        }

        // Per-agent PLV to kick
        let mut plv_sum = 0.0f32;
        let mut plv_count = 0usize;
        for i in 0..E5_N_AGENTS {
            let d_i = wrap_pm_pi(phases[i] - theta_kick);
            plv_buffers[i].push(d_i);
            if plv_buffers[i].is_full() {
                let p = plv_buffers[i].plv();
                if p.is_finite() {
                    plv_sum += p;
                    plv_count += 1;
                }
            }
        }
        let group_plv = if plv_count > 0 {
            plv_sum / plv_count as f32
        } else {
            f32::NAN
        };
        group_plv_series.push((t, group_plv));
    }

    // Collect per-agent final PLV
    let agent_final: Vec<E5AgentFinal> = (0..E5_N_AGENTS)
        .map(|i| E5AgentFinal {
            consonance: consonances[i],
            plv: if plv_buffers[i].is_full() {
                plv_buffers[i].plv()
            } else {
                f32::NAN
            },
        })
        .collect();

    // Pearson r(consonance, final PLV)
    let pearson_r = pearson_r_e5(&agent_final);

    E5VitalityResult {
        group_plv_series,
        agent_final,
        pearson_r,
        condition,
        seed,
    }
}

fn pearson_r_e5(agents: &[E5AgentFinal]) -> f32 {
    let valid: Vec<(f32, f32)> = agents
        .iter()
        .filter(|a| a.plv.is_finite())
        .map(|a| (a.consonance, a.plv))
        .collect();
    if valid.len() < 3 {
        return f32::NAN;
    }
    let n = valid.len() as f32;
    let mean_x = valid.iter().map(|(x, _)| x).sum::<f32>() / n;
    let mean_y = valid.iter().map(|(_, y)| y).sum::<f32>() / n;
    let mut cov = 0.0f32;
    let mut var_x = 0.0f32;
    let mut var_y = 0.0f32;
    for &(x, y) in &valid {
        let dx = x - mean_x;
        let dy = y - mean_y;
        cov += dx * dy;
        var_x += dx * dx;
        var_y += dy * dy;
    }
    let denom = (var_x * var_y).sqrt();
    if denom < 1e-12 { 0.0 } else { cov / denom }
}

fn build_e5_delta_series(
    label: &'static str,
    color: RGBColor,
    lhs: E5Condition,
    rhs: E5Condition,
    seeds: &[u64],
    result_by_cond_seed: &HashMap<(E5Condition, u64), &E5VitalityResult>,
) -> E5DeltaSeries {
    let mut first_len: Option<usize> = None;
    let mut t_axis: Vec<f32> = Vec::new();
    for &seed in seeds {
        let (Some(lhs_res), Some(rhs_res)) = (
            result_by_cond_seed.get(&(lhs, seed)),
            result_by_cond_seed.get(&(rhs, seed)),
        ) else {
            continue;
        };
        let n = lhs_res
            .group_plv_series
            .len()
            .min(rhs_res.group_plv_series.len());
        if n == 0 {
            continue;
        }
        first_len = Some(n);
        t_axis = lhs_res
            .group_plv_series
            .iter()
            .take(n)
            .map(|(t, _)| *t)
            .collect();
        break;
    }

    let n_steps = first_len.unwrap_or(0);
    if n_steps == 0 {
        return E5DeltaSeries {
            label,
            color,
            series: Vec::new(),
        };
    }

    let mut diffs_by_step: Vec<Vec<f32>> = (0..n_steps).map(|_| Vec::new()).collect();
    for &seed in seeds {
        let (Some(lhs_res), Some(rhs_res)) = (
            result_by_cond_seed.get(&(lhs, seed)),
            result_by_cond_seed.get(&(rhs, seed)),
        ) else {
            continue;
        };
        let n = n_steps
            .min(lhs_res.group_plv_series.len())
            .min(rhs_res.group_plv_series.len());
        for (step, diffs) in diffs_by_step.iter_mut().enumerate().take(n) {
            let v_l = lhs_res.group_plv_series[step].1;
            let v_r = rhs_res.group_plv_series[step].1;
            if v_l.is_finite() && v_r.is_finite() {
                diffs.push(v_l - v_r);
            }
        }
    }

    let mut series: Vec<(f32, f32, f32)> = Vec::with_capacity(n_steps);
    for (step, vals) in diffs_by_step.iter().enumerate().take(n_steps) {
        let t = t_axis.get(step).copied().unwrap_or(step as f32 * E5_DT);
        if vals.is_empty() {
            series.push((t, f32::NAN, 0.0));
            continue;
        }
        let mean = vals.iter().copied().sum::<f32>() / vals.len() as f32;
        let var = vals.iter().map(|v| (v - mean).powi(2)).sum::<f32>() / vals.len() as f32;
        let ci95 = 1.96 * var.sqrt() / (vals.len() as f32).sqrt();
        series.push((t, mean, ci95));
    }

    E5DeltaSeries {
        label,
        color,
        series,
    }
}

/// Sigmoid fit with midpoint fixed at C_field = 0:
///   y = base + amplitude · σ(steepness · x)
/// where σ(z) = 1 / (1 + exp(-z)).
/// Grid-search over steepness; OLS for (base, amplitude) at each grid point.
fn fit_e5_sigmoid(points: &[(f32, f32)]) -> Option<E5SigmoidFit> {
    if points.len() < 4 {
        return None;
    }
    let n = points.len() as f32;
    let mut best: Option<E5SigmoidFit> = None;
    let mut best_sse = f32::INFINITY;

    // Grid search over steepness (1..40)
    for i_s in 1..=80 {
        let s = i_s as f32 * 0.5; // 0.5 .. 40.0

        // Compute g_i = σ(s · x_i) for each point
        let mut sum_g = 0.0f32;
        let mut sum_y = 0.0f32;
        let mut sum_gg = 0.0f32;
        let mut sum_gy = 0.0f32;

        for &(x, y) in points {
            let g = 1.0 / (1.0 + (-s * x).exp());
            sum_g += g;
            sum_y += y;
            sum_gg += g * g;
            sum_gy += g * y;
        }

        // OLS: y = base + amplitude · g
        let det = n * sum_gg - sum_g * sum_g;
        if det.abs() < 1e-8 {
            continue;
        }
        let base = (sum_y * sum_gg - sum_g * sum_gy) / det;
        let amplitude = (n * sum_gy - sum_g * sum_y) / det;
        if !base.is_finite() || !amplitude.is_finite() {
            continue;
        }

        let mut sse = 0.0f32;
        for &(x, y) in points {
            let g = 1.0 / (1.0 + (-s * x).exp());
            let y_hat = base + amplitude * g;
            let e = y - y_hat;
            sse += e * e;
        }
        if sse < best_sse {
            best_sse = sse;
            best = Some(E5SigmoidFit {
                base,
                amplitude,
                steepness: s,
            });
        }
    }

    best
}

fn render_e1_plot(
    out_path: &Path,
    _anchor_hz: f32,
    log2_ratio_scan: &[f32],
    perc_h_pot_scan: &[f32],
    perc_r_state01_scan: &[f32],
    perc_c_field_scan: &[f32],
    perc_c_density_scan: &[f32],
) -> Result<(), Box<dyn Error>> {
    let x_min = -1.5f32;
    let x_max = 1.5f32;

    let mut h_points = Vec::new();
    let mut r_points = Vec::new();
    let mut c_points = Vec::new();
    let mut d_points = Vec::new();
    for i in 0..log2_ratio_scan.len() {
        let x = log2_ratio_scan[i];
        if x < x_min || x > x_max {
            continue;
        }
        h_points.push((x, perc_h_pot_scan[i]));
        r_points.push((x, perc_r_state01_scan[i]));
        c_points.push((x, perc_c_field_scan[i]));
        d_points.push((x, perc_c_density_scan[i]));
    }

    let y01_max = 1.05f32;

    // Compute C and D y-ranges before layout so we can size panels proportionally
    let mut c_min = f32::INFINITY;
    let mut c_max = f32::NEG_INFINITY;
    for &(_, y) in &c_points {
        if y.is_finite() {
            c_min = c_min.min(y);
            c_max = c_max.max(y);
        }
    }
    if !c_min.is_finite() || !c_max.is_finite() || (c_max - c_min).abs() < 1e-6 {
        c_min = -1.0;
        c_max = 1.0;
    }
    let pad = 0.05f32;
    let c_y_min = c_min - pad;
    let c_y_max = c_max + pad;
    let c_span = c_y_max - c_y_min;

    let mut d_max_val = f32::NEG_INFINITY;
    for &(_, y) in &d_points {
        if y.is_finite() {
            d_max_val = d_max_val.max(y);
        }
    }
    if !d_max_val.is_finite() {
        d_max_val = 1.0;
    }
    let d_y_min = 0.0f32;
    let d_y_max = d_max_val + pad;
    let d_span = d_y_max - d_y_min;

    // Size C and D panels so their chart areas share the same pixels-per-unit scale.
    // Vertical overhead: top_margin(12) + caption(~48) + bottom_margin + x_label_area
    //   Panel C: 12 + 48 + 24 + 0  = 84
    //   Panel D: 12 + 48 + 12 + 90 = 162
    let total_h: u32 = 1020;
    let h_ab: u32 = 217; // A,B each (15% smaller than equal quarter)
    let remaining = total_h - 2 * h_ab; // 586 for C+D (15% larger)
    let ov_c = 84.0f32;
    let ov_d = 162.0f32;
    let h_d =
        ((d_span * (remaining as f32 - ov_c) + ov_d * c_span) / (c_span + d_span)).round() as u32;
    let h_c = remaining - h_d;

    let root = bitmap_root(out_path, (2200, total_h)).into_drawing_area();
    root.fill(&WHITE)?;
    let (top_half, bottom_half) = root.split_vertically(2 * h_ab);
    let (panel_a, panel_b) = top_half.split_vertically(h_ab);
    let (panel_c, panel_d) = bottom_half.split_vertically(h_c);

    let ratio_guides = [0.5f32, 6.0 / 5.0, 1.25, 4.0 / 3.0, 1.5, 5.0 / 3.0, 2.0];
    let ratio_guides_log2: Vec<f32> = ratio_guides.iter().map(|r| r.log2()).collect();
    let x_grid = [-1.5f32, -1.0, -0.5, 0.0, 0.5, 1.0, 1.5];
    let ratio_guide_style = RGBColor(50, 100, 180).mix(0.55);
    let y_guides = [-0.5f32, 0.0, 0.5, 1.0];

    let mut chart_h = ChartBuilder::on(&panel_a)
        .caption("A: Harmonicity H\u{2080}\u{2081}(f)", ("sans-serif", 48))
        .margin(12)
        .margin_right(25)
        .margin_bottom(24)
        .x_label_area_size(0)
        .y_label_area_size(110)
        .build_cartesian_2d(x_min..x_max, 0.0f32..y01_max)?;

    chart_h
        .configure_mesh()
        .disable_mesh()
        .y_desc("H\u{2080}\u{2081}")
        .x_labels(0)
        .y_labels(6)
        .label_style(("sans-serif", 42).into_font())
        .axis_desc_style(("sans-serif", 46).into_font())
        .draw()?;

    for &x in &x_grid {
        chart_h.draw_series(std::iter::once(PathElement::new(
            vec![(x, 0.0), (x, y01_max)],
            BLACK.mix(0.10),
        )))?;
    }
    for &x in &ratio_guides_log2 {
        if x >= x_min && x <= x_max {
            chart_h.draw_series(std::iter::once(DashedPathElement::new(
                vec![(x, 0.0), (x, y01_max)].into_iter(),
                8,
                6,
                ratio_guide_style,
            )))?;
        }
    }
    for &y in &y_guides {
        if y >= 0.0 && y <= y01_max {
            chart_h.draw_series(std::iter::once(PathElement::new(
                vec![(x_min, y), (x_max, y)],
                BLACK.mix(0.12),
            )))?;
        }
    }

    chart_h.draw_series(LineSeries::new(h_points, &PAL_H))?;

    let mut chart_r = ChartBuilder::on(&panel_b)
        .caption("B: Roughness R\u{2080}\u{2081}(f)", ("sans-serif", 48))
        .margin(12)
        .margin_right(25)
        .margin_bottom(24)
        .x_label_area_size(0)
        .y_label_area_size(110)
        .build_cartesian_2d(x_min..x_max, 0.0f32..y01_max)?;

    chart_r
        .configure_mesh()
        .disable_mesh()
        .y_desc("R\u{2080}\u{2081}")
        .x_labels(0)
        .y_labels(6)
        .label_style(("sans-serif", 42).into_font())
        .axis_desc_style(("sans-serif", 46).into_font())
        .draw()?;

    for &x in &x_grid {
        chart_r.draw_series(std::iter::once(PathElement::new(
            vec![(x, 0.0), (x, y01_max)],
            BLACK.mix(0.10),
        )))?;
    }
    for &x in &ratio_guides_log2 {
        if x >= x_min && x <= x_max {
            chart_r.draw_series(std::iter::once(DashedPathElement::new(
                vec![(x, 0.0), (x, y01_max)].into_iter(),
                8,
                6,
                ratio_guide_style,
            )))?;
        }
    }
    for &y in &y_guides {
        if y >= 0.0 && y <= y01_max {
            chart_r.draw_series(std::iter::once(PathElement::new(
                vec![(x_min, y), (x_max, y)],
                BLACK.mix(0.12),
            )))?;
        }
    }

    chart_r.draw_series(LineSeries::new(r_points, &PAL_R))?;

    let mut chart_c = ChartBuilder::on(&panel_c)
        .caption("C: Consonance field C_field(f)", ("sans-serif", 48))
        .margin(12)
        .margin_right(25)
        .margin_bottom(24)
        .x_label_area_size(0)
        .y_label_area_size(110)
        .build_cartesian_2d(x_min..x_max, c_y_min..c_y_max)?;

    chart_c
        .configure_mesh()
        .disable_mesh()
        .y_desc("C_field")
        .x_labels(0)
        .y_labels(6)
        .label_style(("sans-serif", 42).into_font())
        .axis_desc_style(("sans-serif", 46).into_font())
        .draw()?;

    for &x in &x_grid {
        chart_c.draw_series(std::iter::once(PathElement::new(
            vec![(x, c_y_min), (x, c_y_max)],
            BLACK.mix(0.10),
        )))?;
    }
    for &x in &ratio_guides_log2 {
        if x >= x_min && x <= x_max {
            chart_c.draw_series(std::iter::once(DashedPathElement::new(
                vec![(x, c_y_min), (x, c_y_max)].into_iter(),
                8,
                6,
                ratio_guide_style,
            )))?;
        }
    }
    for &y in &y_guides {
        if y >= c_y_min && y <= c_y_max {
            chart_c.draw_series(std::iter::once(PathElement::new(
                vec![(x_min, y), (x_max, y)],
                BLACK.mix(0.12),
            )))?;
        }
    }

    chart_c.draw_series(LineSeries::new(c_points, &PAL_C))?;

    // Panel D: C_density (non-negative). Same pixels-per-unit scale as Panel C.
    let mut chart_d = ChartBuilder::on(&panel_d)
        .caption("D: Consonance density C_density(f)", ("sans-serif", 48))
        .margin(12)
        .margin_right(25)
        .x_label_area_size(90)
        .y_label_area_size(110)
        .build_cartesian_2d(x_min..x_max, d_y_min..d_y_max)?;

    chart_d
        .configure_mesh()
        .disable_mesh()
        .x_desc("log2(f / f_anchor)")
        .y_desc("C_density")
        .y_labels(3)
        .label_style(("sans-serif", 42).into_font())
        .axis_desc_style(("sans-serif", 46).into_font())
        .draw()?;

    for &x in &x_grid {
        chart_d.draw_series(std::iter::once(PathElement::new(
            vec![(x, d_y_min), (x, d_y_max)],
            BLACK.mix(0.10),
        )))?;
    }
    for &x in &ratio_guides_log2 {
        if x >= x_min && x <= x_max {
            chart_d.draw_series(std::iter::once(DashedPathElement::new(
                vec![(x, d_y_min), (x, d_y_max)].into_iter(),
                8,
                6,
                ratio_guide_style,
            )))?;
        }
    }
    for &y in &y_guides {
        if y >= d_y_min && y <= d_y_max {
            chart_d.draw_series(std::iter::once(PathElement::new(
                vec![(x_min, y), (x_max, y)],
                BLACK.mix(0.12),
            )))?;
        }
    }

    chart_d.draw_series(LineSeries::new(d_points, &PAL_CD))?;

    root.present()?;
    Ok(())
}

fn render_e1_h_mirror_triplet_plot(
    out_path: &Path,
    anchor_hz: f32,
    log2_ratio_scan: &[f32],
    h_m0: &[f32],
    h_m05: &[f32],
    h_m1: &[f32],
) -> Result<(), Box<dyn Error>> {
    let x_min = -3.0f32;
    let x_max = 3.0f32;
    let n = log2_ratio_scan
        .len()
        .min(h_m0.len())
        .min(h_m05.len())
        .min(h_m1.len());

    let mut p_m0 = Vec::new();
    let mut p_m05 = Vec::new();
    let mut p_m1 = Vec::new();
    for i in 0..n {
        let x = log2_ratio_scan[i];
        if x < x_min || x > x_max {
            continue;
        }
        p_m0.push((x, h_m0[i]));
        p_m05.push((x, h_m05[i]));
        p_m1.push((x, h_m1[i]));
    }

    let y_max = h_m0
        .iter()
        .chain(h_m05.iter())
        .chain(h_m1.iter())
        .copied()
        .fold(0.0f32, f32::max)
        .max(1e-6)
        * 1.1;

    let root = bitmap_root(out_path, (1600, 900)).into_drawing_area();
    root.fill(&WHITE)?;

    let ratio_guides = [0.5f32, 6.0 / 5.0, 1.25, 4.0 / 3.0, 1.5, 5.0 / 3.0, 2.0];
    let ratio_guides_log2: Vec<f32> = ratio_guides.iter().map(|r| r.log2()).collect();

    let mut chart = ChartBuilder::on(&root)
        .caption(
            format!(
                "Harmonicity H(f) by mirror_weight | anchor {} Hz",
                anchor_hz
            ),
            ("sans-serif", 24),
        )
        .margin(12)
        .x_label_area_size(42)
        .y_label_area_size(64)
        .build_cartesian_2d(x_min..x_max, 0.0f32..y_max)?;

    chart
        .configure_mesh()
        .x_desc("log2(f / f_anchor)")
        .y_desc("H potential")
        .draw()?;

    for &x in &ratio_guides_log2 {
        if x >= x_min && x <= x_max {
            chart.draw_series(std::iter::once(PathElement::new(
                vec![(x, 0.0), (x, y_max)],
                BLACK.mix(0.15),
            )))?;
        }
    }

    chart
        .draw_series(LineSeries::new(p_m0, &PAL_H))?
        .label("m0 (mirror_weight=0.0)")
        .legend(|(x, y)| PathElement::new(vec![(x, y), (x + 18, y)], PAL_H));
    chart
        .draw_series(LineSeries::new(p_m05, &PAL_C))?
        .label("m05 (mirror_weight=0.5)")
        .legend(|(x, y)| PathElement::new(vec![(x, y), (x + 18, y)], PAL_C));
    chart
        .draw_series(LineSeries::new(p_m1, &PAL_R))?
        .label("m1 (mirror_weight=1.0)")
        .legend(|(x, y)| PathElement::new(vec![(x, y), (x + 18, y)], PAL_R));
    chart
        .configure_series_labels()
        .position(SeriesLabelPosition::UpperRight)
        .background_style(WHITE.mix(0.85))
        .border_style(BLACK.mix(0.25))
        .draw()?;

    root.present()?;
    Ok(())
}

fn render_e1_h_mirror_diff_plot(
    out_path: &Path,
    anchor_hz: f32,
    log2_ratio_scan: &[f32],
    h_m0: &[f32],
    h_m1: &[f32],
) -> Result<(), Box<dyn Error>> {
    let x_min = -3.0f32;
    let x_max = 3.0f32;
    let n = log2_ratio_scan.len().min(h_m0.len()).min(h_m1.len());
    let mut diff_points = Vec::new();
    let mut y_min = f32::INFINITY;
    let mut y_max = f32::NEG_INFINITY;
    for i in 0..n {
        let x = log2_ratio_scan[i];
        if x < x_min || x > x_max {
            continue;
        }
        let d = h_m0[i] - h_m1[i];
        diff_points.push((x, d));
        if d.is_finite() {
            y_min = y_min.min(d);
            y_max = y_max.max(d);
        }
    }
    if !y_min.is_finite() || !y_max.is_finite() {
        y_min = -1.0;
        y_max = 1.0;
    }
    let pad = ((y_max - y_min).abs() * 0.1).max(1e-4);
    let y_lo = (y_min - pad).min(0.0);
    let y_hi = (y_max + pad).max(0.0);

    let root = bitmap_root(out_path, (1600, 700)).into_drawing_area();
    root.fill(&WHITE)?;

    let ratio_guides = [0.5f32, 6.0 / 5.0, 1.25, 4.0 / 3.0, 1.5, 5.0 / 3.0, 2.0];
    let ratio_guides_log2: Vec<f32> = ratio_guides.iter().map(|r| r.log2()).collect();

    let mut chart = ChartBuilder::on(&root)
        .caption(
            format!(
                "Harmonicity Difference H_m0(f) - H_m1(f) | anchor {} Hz",
                anchor_hz
            ),
            ("sans-serif", 24),
        )
        .margin(12)
        .x_label_area_size(42)
        .y_label_area_size(70)
        .build_cartesian_2d(x_min..x_max, y_lo..y_hi)?;

    chart
        .configure_mesh()
        .x_desc("log2(f / f_anchor)")
        .y_desc("H(m0) - H(m1)")
        .draw()?;

    for &x in &ratio_guides_log2 {
        if x >= x_min && x <= x_max {
            chart.draw_series(std::iter::once(PathElement::new(
                vec![(x, y_lo), (x, y_hi)],
                BLACK.mix(0.12),
            )))?;
        }
    }
    chart.draw_series(std::iter::once(PathElement::new(
        vec![(x_min, 0.0), (x_max, 0.0)],
        BLACK.mix(0.35),
    )))?;
    chart.draw_series(LineSeries::new(diff_points, &PAL_C))?;

    root.present()?;
    Ok(())
}

fn plot_e4_mirror_sweep(
    out_dir: &Path,
    anchor_hz: f32,
    emit_hist_files: bool,
    emit_kernel_gate: bool,
    emit_wr_probe: bool,
    emit_debug_fit_metrics: bool,
) -> Result<(), Box<dyn Error>> {
    let primary_bin = E4_BIN_WIDTHS[0];
    let primary_eps = E4_EPS_CENTS[0];

    if !emit_debug_fit_metrics {
        purge_e4_fit_debug_outputs(out_dir)?;
    }
    purge_e4_legacy_outputs(out_dir)?;
    let weights = build_weight_grid(E4_WEIGHT_COARSE_STEP);
    let (_run_records, hist_records, _tail_rows, tail_agent_rows, tail_landscape_rows) =
        run_e4_sweep_for_weights(
            out_dir,
            anchor_hz,
            &weights,
            &E4_SEEDS,
            primary_bin,
            &E4_EPS_CENTS,
            emit_hist_files,
            true,
        )?;

    let tail_landscape_csv_path = out_dir.join("e4_tail_landscape.csv");
    write_with_log(
        &tail_landscape_csv_path,
        e4_tail_landscape_csv(&tail_landscape_rows),
    )?;

    let bind_metrics = e4_binding_metrics_from_tail_landscape(&tail_landscape_rows);
    let bind_summary = e4_binding_summary_rows(&bind_metrics);
    let binding_metrics_path = out_dir.join("e4_binding_metrics.csv");
    write_with_log(&binding_metrics_path, e4_binding_metrics_csv(&bind_metrics))?;
    let binding_summary_path = out_dir.join("e4_binding_summary.csv");
    write_with_log(&binding_summary_path, e4_binding_summary_csv(&bind_summary))?;
    let binding_metrics_raw_path = out_dir.join("paper_e4_binding_metrics_raw.csv");
    write_with_log(
        &binding_metrics_raw_path,
        e4_binding_metrics_raw_csv(&bind_metrics),
    )?;
    let binding_metrics_summary_path = out_dir.join("paper_e4_binding_metrics_summary.csv");
    write_with_log(
        &binding_metrics_summary_path,
        e4_binding_metrics_summary_csv(&bind_summary),
    )?;

    let binding_phase_png_path = out_dir.join("paper_e4_binding_phase_diagram.png");
    render_e4_binding_phase_diagram_png(&binding_phase_png_path, &bind_summary)?;
    let harmonic_tilt_png_path = out_dir.join("paper_e4_harmonic_tilt.png");
    render_e4_harmonic_tilt_png(&harmonic_tilt_png_path, &bind_summary)?;
    let harmonic_tilt_scatter_path = out_dir.join("paper_e4_harmonic_tilt_scatter.png");
    render_e4_harmonic_tilt_scatter_png(&harmonic_tilt_scatter_path, &bind_metrics)?;
    let overtone_rate_path = out_dir.join("paper_e4_overtone_regime_rate.png");
    render_e4_overtone_regime_rate_png(&overtone_rate_path, &bind_metrics)?;
    let bind_main_path = out_dir.join("paper_e4_bind_vs_weight.svg");
    render_e4_bind_vs_weight(&bind_main_path, &bind_summary)?;
    let fingerprint_path = out_dir.join("paper_e4_interval_fingerprint_heatmap.svg");
    render_e4_interval_heatmap(&fingerprint_path, &hist_records, primary_bin)?;
    run_e4_step_and_hysteresis_protocol(out_dir, anchor_hz, primary_eps)?;
    write_e4_env_2d_sweep_outputs(out_dir, &tail_agent_rows, anchor_hz)?;
    if emit_debug_fit_metrics {
        write_e4_debug_fit_outputs(out_dir, &tail_agent_rows)?;
    }
    if emit_wr_probe {
        plot_e4_mirror_sweep_wr_cut(out_dir, anchor_hz)?;
    }

    if emit_kernel_gate {
        let kernel_gate_path = out_dir.join("paper_e4_kernel_gate.svg");
        render_e4_kernel_gate(&kernel_gate_path, anchor_hz)?;
    }

    Ok(())
}

