fn normalize_freq_ratios(freqs: &[f32]) -> Vec<f32> {
    let mut clean: Vec<f32> = freqs
        .iter()
        .copied()
        .filter(|f| f.is_finite() && *f > 0.0)
        .collect();
    if clean.is_empty() {
        return Vec::new();
    }
    clean.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let mid = clean.len() / 2;
    let median = if clean.len().is_multiple_of(2) {
        0.5 * (clean[mid - 1] + clean[mid])
    } else {
        clean[mid]
    };
    if !median.is_finite() || median <= 0.0 {
        return Vec::new();
    }
    clean
        .into_iter()
        .map(|f| f / median)
        .filter(|r| r.is_finite() && *r > 0.0)
        .collect()
}

fn harmonic_index_penalty(n: u32) -> f32 {
    let n = n.max(1) as f32;
    let beta = E4_BIND_RHO.max(0.0);
    (-(beta * (n - 1.0))).exp()
}

fn root_candidate_score(ratios: &[f32], candidate_root: f32) -> f32 {
    if !candidate_root.is_finite() || candidate_root <= 0.0 {
        return 0.0;
    }
    let sigma = E4_BIND_SIGMA_CENTS.max(1e-6);
    let n_max = E4_BIND_MAX_HARMONIC.max(1) as i32;
    let mut total = 0.0f32;
    let mut count = 0usize;
    for &ratio in ratios {
        if !ratio.is_finite() || ratio <= 0.0 {
            continue;
        }
        let mut n = (ratio / candidate_root).round() as i32;
        n = n.clamp(1, n_max);
        let target = candidate_root * n as f32;
        if !target.is_finite() || target <= 0.0 {
            continue;
        }
        let err_cents = 1200.0 * (ratio / target).log2();
        let score = (-0.5 * (err_cents / sigma).powi(2)).exp() * harmonic_index_penalty(n as u32);
        total += score;
        count += 1;
    }
    if count == 0 {
        0.0
    } else {
        total / count as f32
    }
}

fn ceiling_candidate_score(ratios: &[f32], candidate_ceiling: f32) -> f32 {
    if !candidate_ceiling.is_finite() || candidate_ceiling <= 0.0 {
        return 0.0;
    }
    let sigma = E4_BIND_SIGMA_CENTS.max(1e-6);
    let n_max = E4_BIND_MAX_HARMONIC.max(1) as i32;
    let mut total = 0.0f32;
    let mut count = 0usize;
    for &ratio in ratios {
        if !ratio.is_finite() || ratio <= 0.0 {
            continue;
        }
        let mut n = (candidate_ceiling / ratio).round() as i32;
        n = n.clamp(1, n_max);
        let target = candidate_ceiling / n as f32;
        if !target.is_finite() || target <= 0.0 {
            continue;
        }
        let err_cents = 1200.0 * (ratio / target).log2();
        let score = (-0.5 * (err_cents / sigma).powi(2)).exp() * harmonic_index_penalty(n as u32);
        total += score;
        count += 1;
    }
    if count == 0 {
        0.0
    } else {
        total / count as f32
    }
}

fn unique_candidates(mut raw: Vec<f32>) -> Vec<f32> {
    raw.retain(|f| f.is_finite() && *f > 0.0);
    for f in &mut raw {
        *f = (*f * 10_000.0).round() / 10_000.0;
    }
    raw.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    raw.dedup_by(|a, b| (*a - *b).abs() < 1e-6);
    raw
}

fn root_affinity_from_freqs(freqs: &[f32]) -> f32 {
    let ratios = normalize_freq_ratios(freqs);
    if ratios.is_empty() {
        return 0.0;
    }
    let mut candidates = Vec::with_capacity(ratios.len() * E4_BIND_MAX_HARMONIC as usize);
    for &ratio in &ratios {
        for n in 1..=E4_BIND_MAX_HARMONIC {
            candidates.push(ratio / n as f32);
        }
    }
    let mut candidates = unique_candidates(candidates);
    candidates.retain(|c| *c <= 1.0 + 1e-4);
    if candidates.is_empty() {
        return 0.0;
    }
    candidates.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let top_k = E4_BIND_TOP_CANDIDATES.max(1).min(candidates.len());
    let mut best = 0.0f32;
    for &candidate in candidates.iter().take(top_k) {
        best = best.max(root_candidate_score(&ratios, candidate));
    }
    best
}

fn overtone_affinity_from_freqs(freqs: &[f32]) -> f32 {
    let ratios = normalize_freq_ratios(freqs);
    if ratios.is_empty() {
        return 0.0;
    }
    let mut candidates = Vec::with_capacity(ratios.len() * E4_BIND_MAX_HARMONIC as usize);
    for &ratio in &ratios {
        for n in 1..=E4_BIND_MAX_HARMONIC {
            candidates.push(ratio * n as f32);
        }
    }
    let mut candidates = unique_candidates(candidates);
    candidates.retain(|c| *c >= 1.0 - 1e-4);
    if candidates.is_empty() {
        return 0.0;
    }
    candidates.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal));
    let top_k = E4_BIND_TOP_CANDIDATES.max(1).min(candidates.len());
    let mut best = 0.0f32;
    for &candidate in candidates.iter().take(top_k) {
        best = best.max(ceiling_candidate_score(&ratios, candidate));
    }
    best
}

#[derive(Clone, Copy, Debug)]
struct BindEval {
    root_affinity: f32,
    overtone_affinity: f32,
    binding_strength: f32,
    harmonic_tilt: f32,
}

fn bind_eval_from_freqs(freqs: &[f32]) -> BindEval {
    let clean_freqs: Vec<f32> = freqs
        .iter()
        .copied()
        .filter(|f| f.is_finite() && *f > 0.0)
        .collect();
    if clean_freqs.is_empty() {
        return BindEval {
            root_affinity: 0.0,
            overtone_affinity: 0.0,
            binding_strength: 0.0,
            harmonic_tilt: 0.0,
        };
    }
    // Voices only (anchor excluded): this keeps the regime metric tied to population structure.
    let root_affinity = root_affinity_from_freqs(&clean_freqs);
    let overtone_affinity = overtone_affinity_from_freqs(&clean_freqs);
    let binding_strength = root_affinity + overtone_affinity;
    let denom = binding_strength + 1e-6;
    let harmonic_tilt = ((root_affinity - overtone_affinity) / denom).clamp(-1.0, 1.0);
    BindEval {
        root_affinity,
        overtone_affinity,
        binding_strength,
        harmonic_tilt,
    }
}

#[allow(dead_code)]
fn bind_scores_from_freqs(freqs: &[f32]) -> (f32, f32, f32) {
    let eval = bind_eval_from_freqs(freqs);
    (
        eval.root_affinity,
        eval.overtone_affinity,
        eval.harmonic_tilt,
    )
}

fn anchored_fit_from_ratios(ratios: &[f32]) -> f32 {
    let sigma = E4_BIND_SIGMA_CENTS.max(1e-6);
    let n_max = E4_BIND_MAX_HARMONIC.max(1) as i32;
    let mut total = 0.0f32;
    let mut count = 0usize;
    for &ratio in ratios {
        if !ratio.is_finite() || ratio <= 0.0 {
            continue;
        }
        let mut n = ratio.round() as i32;
        n = n.clamp(1, n_max);
        let target = n as f32;
        let err_cents = 1200.0 * (ratio / target).log2();
        let score = (-0.5 * (err_cents / sigma).powi(2)).exp() * harmonic_index_penalty(n as u32);
        total += score;
        count += 1;
    }
    if count == 0 {
        0.0
    } else {
        total / count as f32
    }
}

fn bind_scores_anchor_from_freqs(anchor_hz: f32, freqs: &[f32]) -> (f32, f32, f32) {
    if !anchor_hz.is_finite() || anchor_hz <= 0.0 {
        return (0.0, 0.0, 0.0);
    }
    let ratios: Vec<f32> = freqs
        .iter()
        .copied()
        .filter(|f| f.is_finite() && *f > 0.0)
        .map(|f| f / anchor_hz)
        .filter(|r| r.is_finite() && *r > 0.0)
        .collect();
    if ratios.is_empty() {
        return (0.0, 0.0, 0.0);
    }
    let root_affinity_anchor = anchored_fit_from_ratios(&ratios);
    let inv_ratios: Vec<f32> = ratios
        .iter()
        .copied()
        .filter(|r| *r > 0.0)
        .map(|r| 1.0 / r)
        .collect();
    let overtone_affinity_anchor = anchored_fit_from_ratios(&inv_ratios);
    let denom = root_affinity_anchor + overtone_affinity_anchor + 1e-6;
    let harmonic_tilt_anchor = (root_affinity_anchor - overtone_affinity_anchor) / denom;
    (
        root_affinity_anchor,
        overtone_affinity_anchor,
        harmonic_tilt_anchor.clamp(-1.0, 1.0),
    )
}

fn sample_weighted_index(weights: &[f32], rng: &mut StdRng) -> Option<usize> {
    if weights.is_empty() {
        return None;
    }
    let mut total = 0.0f32;
    for &w in weights {
        if w.is_finite() && w > 0.0 {
            total += w;
        }
    }
    if total <= 0.0 {
        return Some(rng.random_range(0..weights.len()));
    }
    let mut x = rng.random_range(0.0..total);
    for (i, &w) in weights.iter().enumerate() {
        let ww = if w.is_finite() && w > 0.0 { w } else { 0.0 };
        if x <= ww {
            return Some(i);
        }
        x -= ww;
    }
    Some(weights.len().saturating_sub(1))
}

fn oracle1_harmonic_tilt_from_peaks(peaks: &[E4PeakRow], k: usize) -> f32 {
    let k = k.max(1);
    let freqs: Vec<f32> = peaks.iter().take(k).map(|p| p.freq_hz).collect();
    bind_eval_from_freqs(&freqs).harmonic_tilt
}

fn oracle2_harmonic_tilt_from_peaks(
    peaks: &[E4PeakRow],
    top_n: usize,
    k: usize,
    trials: usize,
    seed: u64,
) -> (f32, f32, f32) {
    if peaks.is_empty() || trials == 0 {
        return (0.0, 0.0, 0.0);
    }
    let top_n = top_n.max(1).min(peaks.len());
    let k = k.max(1);
    let pool = &peaks[..top_n];
    let weights: Vec<f32> = pool.iter().map(|p| p.c_value.max(0.0)).collect();
    let mut rng = StdRng::seed_from_u64(seed);
    let mut deltas = Vec::with_capacity(trials);
    for _ in 0..trials {
        let mut freqs = Vec::with_capacity(k);
        for _ in 0..k {
            let idx = sample_weighted_index(&weights, &mut rng).unwrap_or(0);
            freqs.push(pool[idx].freq_hz);
        }
        deltas.push(bind_eval_from_freqs(&freqs).harmonic_tilt);
    }
    bootstrap_mean_ci95(&deltas, E4_BOOTSTRAP_ITERS, seed ^ 0xB007_5EED)
}

fn e4_wr_oracle_run_rows(
    bind_runs: &[E4WrBindRunRow],
    grouped_freqs: &std::collections::HashMap<(i32, i32, u64), Vec<f32>>,
    space: &Log2Space,
    anchor_hz: f32,
    du_scan: &[f32],
    population_size: usize,
) -> Vec<E4WrOracleRunRow> {
    let mut out = Vec::new();
    for run in bind_runs {
        let key = (float_key(run.wr), float_key(run.mirror_weight), run.seed);
        let Some(freqs) = grouped_freqs.get(&key) else {
            continue;
        };
        let scan =
            compute_e4_landscape_scans(space, anchor_hz, run.wr, run.mirror_weight, freqs, du_scan);
        let peaks = extract_peak_rows_from_c_scan(space, anchor_hz, &scan, E4_ORACLE_TOP_N.max(1));
        let oracle1 = oracle1_harmonic_tilt_from_peaks(&peaks, population_size);
        let oracle_seed = E4_WR_BASE_SEED
            ^ (key.0 as i64 as u64).wrapping_mul(0x9E37_79B9)
            ^ (key.1 as i64 as u64).wrapping_mul(0x85EB_CA6B)
            ^ key.2.wrapping_mul(0xC2B2_AE35);
        let (oracle2_mean, _oracle2_lo, _oracle2_hi) = oracle2_harmonic_tilt_from_peaks(
            &peaks,
            E4_ORACLE_TOP_N,
            population_size,
            E4_ORACLE_SAMPLE_TRIALS,
            oracle_seed,
        );
        out.push(E4WrOracleRunRow {
            wr: run.wr,
            mirror_weight: run.mirror_weight,
            seed: run.seed,
            n_peaks: peaks.len(),
            agent_harmonic_tilt: run.harmonic_tilt,
            oracle1_harmonic_tilt: oracle1,
            oracle2_harmonic_tilt: oracle2_mean,
        });
    }
    out.sort_by(|a, b| {
        a.wr.partial_cmp(&b.wr)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| {
                a.mirror_weight
                    .partial_cmp(&b.mirror_weight)
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
            .then_with(|| a.seed.cmp(&b.seed))
    });
    out
}

fn e4_wr_oracle_runs_csv(rows: &[E4WrOracleRunRow]) -> String {
    let mut out = String::from(
        "wr,mirror_weight,seed,n_peaks,harmonic_tilt_agent,harmonic_tilt_oracle1,harmonic_tilt_oracle2\n",
    );
    for row in rows {
        out.push_str(&format!(
            "{:.3},{:.3},{},{},{:.6},{:.6},{:.6}\n",
            row.wr,
            row.mirror_weight,
            row.seed,
            row.n_peaks,
            row.agent_harmonic_tilt,
            row.oracle1_harmonic_tilt,
            row.oracle2_harmonic_tilt
        ));
    }
    out
}

fn e4_wr_oracle_rows_from_runs(rows: &[E4WrOracleRunRow]) -> Vec<E4WrOracleRow> {
    let mut grouped: std::collections::HashMap<(i32, i32), Vec<&E4WrOracleRunRow>> =
        std::collections::HashMap::new();
    for row in rows {
        grouped
            .entry((float_key(row.wr), float_key(row.mirror_weight)))
            .or_default()
            .push(row);
    }
    let mut out = Vec::with_capacity(grouped.len());
    for ((wr_key, mirror_key), group) in grouped {
        let agent_vals: Vec<f32> = group.iter().map(|r| r.agent_harmonic_tilt).collect();
        let oracle1_vals: Vec<f32> = group.iter().map(|r| r.oracle1_harmonic_tilt).collect();
        let oracle2_vals: Vec<f32> = group.iter().map(|r| r.oracle2_harmonic_tilt).collect();
        let mean_peaks = group.iter().map(|r| r.n_peaks as f32).sum::<f32>() / group.len() as f32;
        let seed = E4_BOOTSTRAP_SEED
            ^ 0x0A_C1E_u64
            ^ (wr_key as i64 as u64).wrapping_mul(0x9E37_79B9)
            ^ (mirror_key as i64 as u64).wrapping_mul(0x85EB_CA6B);
        let (agent_mean, _agent_lo, _agent_hi) =
            bootstrap_mean_ci95(&agent_vals, E4_BOOTSTRAP_ITERS, seed ^ 0x11);
        let (oracle1_mean, oracle1_lo, oracle1_hi) =
            bootstrap_mean_ci95(&oracle1_vals, E4_BOOTSTRAP_ITERS, seed ^ 0x22);
        let (oracle2_mean, oracle2_lo, oracle2_hi) =
            bootstrap_mean_ci95(&oracle2_vals, E4_BOOTSTRAP_ITERS, seed ^ 0x33);
        out.push(E4WrOracleRow {
            wr: float_from_key(wr_key),
            mirror_weight: float_from_key(mirror_key),
            n_seeds: group.len(),
            n_peaks: mean_peaks.round().max(0.0) as usize,
            agent_harmonic_tilt: agent_mean.clamp(-1.0, 1.0),
            oracle1_harmonic_tilt: oracle1_mean.clamp(-1.0, 1.0),
            oracle1_harmonic_tilt_ci_lo: oracle1_lo.clamp(-1.0, 1.0),
            oracle1_harmonic_tilt_ci_hi: oracle1_hi.clamp(-1.0, 1.0),
            oracle2_harmonic_tilt_mean: oracle2_mean.clamp(-1.0, 1.0),
            oracle2_harmonic_tilt_ci_lo: oracle2_lo.clamp(-1.0, 1.0),
            oracle2_harmonic_tilt_ci_hi: oracle2_hi.clamp(-1.0, 1.0),
        });
    }
    out.sort_by(|a, b| {
        a.wr.partial_cmp(&b.wr)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| {
                a.mirror_weight
                    .partial_cmp(&b.mirror_weight)
                    .unwrap_or(std::cmp::Ordering::Equal)
            })
    });
    out
}

fn e4_wr_oracle_csv(rows: &[E4WrOracleRow]) -> String {
    let mut out = String::from(
        "wr,mirror_weight,n_seeds,n_peaks,harmonic_tilt_agent,harmonic_tilt_oracle1,harmonic_tilt_oracle1_ci_lo,harmonic_tilt_oracle1_ci_hi,harmonic_tilt_oracle2_mean,harmonic_tilt_oracle2_ci_lo,harmonic_tilt_oracle2_ci_hi\n",
    );
    for row in rows {
        out.push_str(&format!(
            "{:.3},{:.3},{},{},{:.6},{:.6},{:.6},{:.6},{:.6},{:.6},{:.6}\n",
            row.wr,
            row.mirror_weight,
            row.n_seeds,
            row.n_peaks,
            row.agent_harmonic_tilt,
            row.oracle1_harmonic_tilt,
            row.oracle1_harmonic_tilt_ci_lo,
            row.oracle1_harmonic_tilt_ci_hi,
            row.oracle2_harmonic_tilt_mean,
            row.oracle2_harmonic_tilt_ci_lo,
            row.oracle2_harmonic_tilt_ci_hi
        ));
    }
    out
}

fn harmonic_tilt_from_affinities(root_affinity: f32, overtone_affinity: f32) -> f32 {
    let denom = root_affinity + overtone_affinity + 1e-6;
    if !denom.is_finite() || denom <= 0.0 {
        return 0.0;
    }
    let tilt = (root_affinity - overtone_affinity) / denom;
    if tilt.is_finite() {
        tilt.clamp(-1.0, 1.0)
    } else {
        0.0
    }
}

fn e4_fit_metrics_from_tail_agents(rows: &[E4TailAgentRow]) -> Vec<E4FitMetricRow> {
    let mut latest_step: std::collections::HashMap<(i32, u64), u32> =
        std::collections::HashMap::new();
    for row in rows {
        latest_step
            .entry((float_key(row.mirror_weight), row.seed))
            .and_modify(|step| *step = (*step).max(row.step))
            .or_insert(row.step);
    }

    let mut grouped: std::collections::HashMap<(i32, u64), Vec<f32>> =
        std::collections::HashMap::new();
    for row in rows {
        if !row.freq_hz.is_finite() || row.freq_hz <= 0.0 {
            continue;
        }
        let key = (float_key(row.mirror_weight), row.seed);
        let Some(step) = latest_step.get(&key).copied() else {
            continue;
        };
        if row.step != step {
            continue;
        }
        grouped.entry(key).or_default().push(row.freq_hz);
    }

    let mut out = Vec::new();
    for ((mw_key, seed), freqs) in grouped {
        if freqs.is_empty() {
            continue;
        }
        let eval = bind_eval_from_freqs(&freqs);
        let step = latest_step.get(&(mw_key, seed)).copied().unwrap_or(0);
        out.push(E4FitMetricRow {
            mirror_weight: float_from_key(mw_key),
            seed,
            step,
            n_agents: freqs.len(),
            root_fit: eval.root_affinity,
            ceiling_fit: eval.overtone_affinity,
            binding_strength: eval.binding_strength,
            harmonic_tilt: eval.harmonic_tilt,
        });
    }
    out.sort_by(|a, b| {
        a.mirror_weight
            .partial_cmp(&b.mirror_weight)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.seed.cmp(&b.seed))
    });
    out
}

fn e4_fit_summary_rows(rows: &[E4FitMetricRow]) -> Vec<E4FitSummaryRow> {
    let mut by_weight: std::collections::HashMap<i32, Vec<&E4FitMetricRow>> =
        std::collections::HashMap::new();
    for row in rows {
        by_weight
            .entry(float_key(row.mirror_weight))
            .or_default()
            .push(row);
    }
    let mut out = Vec::new();
    for (weight_key, group) in by_weight {
        let root_vals: Vec<f32> = group.iter().map(|r| r.root_fit).collect();
        let ceiling_vals: Vec<f32> = group.iter().map(|r| r.ceiling_fit).collect();
        let binding_vals: Vec<f32> = root_vals
            .iter()
            .zip(ceiling_vals.iter())
            .map(|(r, c)| *r + *c)
            .collect();
        let tilt_vals: Vec<f32> = root_vals
            .iter()
            .zip(ceiling_vals.iter())
            .map(|(r, c)| harmonic_tilt_from_affinities(*r, *c))
            .collect();
        let seed =
            E4_BOOTSTRAP_SEED ^ 0xF17E_u64 ^ (weight_key as i64 as u64).wrapping_mul(0x9E37_79B9);
        let (root_mean, root_ci_lo, root_ci_hi) =
            bootstrap_mean_ci95(&root_vals, E4_BOOTSTRAP_ITERS, seed ^ 0x11);
        let (ceiling_mean, ceiling_ci_lo, ceiling_ci_hi) =
            bootstrap_mean_ci95(&ceiling_vals, E4_BOOTSTRAP_ITERS, seed ^ 0x22);
        let (_binding_mean, binding_ci_lo, binding_ci_hi) =
            bootstrap_mean_ci95(&binding_vals, E4_BOOTSTRAP_ITERS, seed ^ 0x2B);
        let (_tilt_mean, tilt_ci_lo, tilt_ci_hi) =
            bootstrap_mean_ci95(&tilt_vals, E4_BOOTSTRAP_ITERS, seed ^ 0x33);
        let binding_mean = root_mean + ceiling_mean;
        let tilt_mean = harmonic_tilt_from_affinities(root_mean, ceiling_mean);
        out.push(E4FitSummaryRow {
            mirror_weight: float_from_key(weight_key),
            root_fit_mean: root_mean,
            root_fit_ci_lo: root_ci_lo,
            root_fit_ci_hi: root_ci_hi,
            ceiling_fit_mean: ceiling_mean,
            ceiling_fit_ci_lo: ceiling_ci_lo,
            ceiling_fit_ci_hi: ceiling_ci_hi,
            binding_strength_mean: binding_mean,
            binding_strength_ci_lo: binding_ci_lo,
            binding_strength_ci_hi: binding_ci_hi,
            harmonic_tilt_mean: tilt_mean,
            harmonic_tilt_ci_lo: tilt_ci_lo,
            harmonic_tilt_ci_hi: tilt_ci_hi,
            n_seeds: group.len(),
        });
    }
    out.sort_by(|a, b| {
        a.mirror_weight
            .partial_cmp(&b.mirror_weight)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    out
}

