fn render_e4_harmonic_tilt_scatter_png(
    out_path: &Path,
    rows: &[E4BindingMetricRow],
) -> Result<(), Box<dyn Error>> {
    if rows.is_empty() {
        return Ok(());
    }
    let mut y_min = f32::INFINITY;
    let mut y_max = f32::NEG_INFINITY;
    for row in rows {
        y_min = y_min.min(row.harmonic_tilt);
        y_max = y_max.max(row.harmonic_tilt);
    }
    if !y_min.is_finite() || !y_max.is_finite() {
        y_min = -0.1;
        y_max = 0.1;
    }
    if (y_max - y_min).abs() < 1e-6 {
        y_min -= 0.1;
        y_max += 0.1;
    }
    let pad = 0.15 * (y_max - y_min);

    log_output_path(out_path);
    let root = BitMapBackend::new(out_path, (1400, 850)).into_drawing_area();
    root.fill(&WHITE)?;
    let mut chart = ChartBuilder::on(&root)
        .caption(
            "E4 Harmonic Tilt (τ) by seed and mirror_weight",
            ("sans-serif", 24),
        )
        .margin(12)
        .x_label_area_size(46)
        .y_label_area_size(68)
        .build_cartesian_2d(0.0f32..1.0f32, (y_min - pad)..(y_max + pad))?;

    chart
        .configure_mesh()
        .x_desc("mirror_weight")
        .y_desc("Harmonic Tilt (τ)")
        .draw()?;

    chart.draw_series(std::iter::once(PathElement::new(
        vec![(0.0, 0.0), (1.0, 0.0)],
        BLACK.mix(0.8).stroke_width(2),
    )))?;

    chart.draw_series(rows.iter().map(|row| {
        let jitter = ((row.seed.wrapping_mul(0x9E37_79B9) % 1000) as f32 / 1000.0 - 0.5) * 0.02;
        let x = (row.mirror_weight + jitter).clamp(0.0, 1.0);
        let color = if row.harmonic_tilt < 0.0 {
            PAL_R.mix(0.85)
        } else {
            PAL_H.mix(0.85)
        };
        Circle::new((x, row.harmonic_tilt), 3, color.filled())
    }))?;

    root.present()?;
    Ok(())
}

fn wilson_ci95(successes: usize, n: usize) -> (f32, f32) {
    if n == 0 {
        return (0.0, 0.0);
    }
    let z = 1.96f32;
    let nf = n as f32;
    let phat = successes as f32 / nf;
    let denom = 1.0 + z * z / nf;
    let center = (phat + z * z / (2.0 * nf)) / denom;
    let half = (z / denom) * ((phat * (1.0 - phat) / nf + z * z / (4.0 * nf * nf)).sqrt());
    ((center - half).max(0.0), (center + half).min(1.0))
}

fn render_e4_overtone_regime_rate_png(
    out_path: &Path,
    rows: &[E4BindingMetricRow],
) -> Result<(), Box<dyn Error>> {
    if rows.is_empty() {
        return Ok(());
    }
    let mut grouped: std::collections::HashMap<i32, Vec<&E4BindingMetricRow>> =
        std::collections::HashMap::new();
    for row in rows {
        grouped
            .entry(float_key(row.mirror_weight))
            .or_default()
            .push(row);
    }
    let mut series: Vec<(f32, f32, f32, f32)> = grouped
        .into_iter()
        .map(|(key, vals)| {
            let n = vals.len();
            let k = vals.iter().filter(|r| r.harmonic_tilt < 0.0).count();
            let p = if n > 0 { k as f32 / n as f32 } else { 0.0 };
            let (lo, hi) = wilson_ci95(k, n);
            (float_from_key(key), p, lo, hi)
        })
        .collect();
    series.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));

    log_output_path(out_path);
    let root = BitMapBackend::new(out_path, (1400, 850)).into_drawing_area();
    root.fill(&WHITE)?;
    let mut chart = ChartBuilder::on(&root)
        .caption(
            "E4 Overtone regime rate: P(τ < 0) vs mirror_weight",
            ("sans-serif", 24),
        )
        .margin(12)
        .x_label_area_size(46)
        .y_label_area_size(68)
        .build_cartesian_2d(0.0f32..1.0f32, 0.0f32..1.0f32)?;

    chart
        .configure_mesh()
        .x_desc("mirror_weight")
        .y_desc("P(τ < 0)")
        .draw()?;

    chart.draw_series(LineSeries::new(
        series.iter().map(|(w, p, _, _)| (*w, *p)),
        PAL_R.mix(0.9).stroke_width(3),
    ))?;
    chart.draw_series(
        series
            .iter()
            .map(|(w, p, _, _)| Circle::new((*w, *p), 5, PAL_R.mix(0.9).filled())),
    )?;
    chart.draw_series(series.iter().map(|(w, _, lo, hi)| {
        PathElement::new(vec![(*w, *lo), (*w, *hi)], PAL_R.mix(0.7).stroke_width(2))
    }))?;

    root.present()?;
    Ok(())
}

fn render_e4_binding_phase_diagram_png(
    out_path: &Path,
    summary_rows: &[E4BindingSummaryRow],
) -> Result<(), Box<dyn Error>> {
    if summary_rows.is_empty() {
        return Ok(());
    }
    let mut rows = summary_rows.to_vec();
    rows.sort_by(|a, b| {
        a.mirror_weight
            .partial_cmp(&b.mirror_weight)
            .unwrap_or(std::cmp::Ordering::Equal)
    });

    let mut y_max = 0.0f32;
    for row in &rows {
        y_max = y_max
            .max(row.root_affinity_ci_hi)
            .max(row.overtone_affinity_ci_hi)
            .max(row.binding_strength_ci_hi);
    }
    y_max = (y_max * 1.15).max(1e-4);

    log_output_path(out_path);
    let root = BitMapBackend::new(out_path, (1400, 850)).into_drawing_area();
    root.fill(&WHITE)?;
    let mut chart = ChartBuilder::on(&root)
        .caption(
            "E4 Binding Phase Diagram: R_A / O_A / S (mean ± 95% CI)",
            ("sans-serif", 24),
        )
        .margin(12)
        .x_label_area_size(46)
        .y_label_area_size(68)
        .build_cartesian_2d(0.0f32..1.0f32, 0.0f32..y_max)?;

    chart
        .configure_mesh()
        .x_desc("mirror_weight")
        .y_desc("affinity / strength")
        .draw()?;

    if rows.len() >= 2 {
        let mut root_band: Vec<(f32, f32)> = rows
            .iter()
            .map(|row| (row.mirror_weight, row.root_affinity_ci_hi))
            .collect();
        root_band.extend(
            rows.iter()
                .rev()
                .map(|row| (row.mirror_weight, row.root_affinity_ci_lo)),
        );
        chart.draw_series(std::iter::once(Polygon::new(
            root_band,
            PAL_H.mix(0.14).filled(),
        )))?;

        let mut ceiling_band: Vec<(f32, f32)> = rows
            .iter()
            .map(|row| (row.mirror_weight, row.overtone_affinity_ci_hi))
            .collect();
        ceiling_band.extend(
            rows.iter()
                .rev()
                .map(|row| (row.mirror_weight, row.overtone_affinity_ci_lo)),
        );
        chart.draw_series(std::iter::once(Polygon::new(
            ceiling_band,
            PAL_R.mix(0.12).filled(),
        )))?;

        let mut binding_band: Vec<(f32, f32)> = rows
            .iter()
            .map(|row| (row.mirror_weight, row.binding_strength_ci_hi))
            .collect();
        binding_band.extend(
            rows.iter()
                .rev()
                .map(|row| (row.mirror_weight, row.binding_strength_ci_lo)),
        );
        chart.draw_series(std::iter::once(Polygon::new(
            binding_band,
            PAL_CD.mix(0.10).filled(),
        )))?;
    }

    chart
        .draw_series(LineSeries::new(
            rows.iter()
                .map(|row| (row.mirror_weight, row.root_affinity_mean)),
            PAL_H.mix(0.95).stroke_width(3),
        ))?
        .label("Root Affinity (R_A)")
        .legend(|(x, y)| PathElement::new(vec![(x, y), (x + 24, y)], PAL_H.stroke_width(3)));
    chart.draw_series(rows.iter().map(|row| {
        Circle::new(
            (row.mirror_weight, row.root_affinity_mean),
            5,
            PAL_H.mix(0.95).filled(),
        )
    }))?;

    chart
        .draw_series(LineSeries::new(
            rows.iter()
                .map(|row| (row.mirror_weight, row.overtone_affinity_mean)),
            PAL_R.mix(0.92).stroke_width(3),
        ))?
        .label("Overtone Affinity (O_A)")
        .legend(|(x, y)| PathElement::new(vec![(x, y), (x + 24, y)], PAL_R.stroke_width(3)));
    chart.draw_series(rows.iter().map(|row| {
        TriangleMarker::new(
            (row.mirror_weight, row.overtone_affinity_mean),
            7,
            PAL_R.mix(0.92).filled(),
        )
    }))?;

    chart
        .draw_series(LineSeries::new(
            rows.iter()
                .map(|row| (row.mirror_weight, row.binding_strength_mean)),
            PAL_CD.mix(0.90).stroke_width(3),
        ))?
        .label("Binding Strength (S)")
        .legend(|(x, y)| PathElement::new(vec![(x, y), (x + 24, y)], PAL_CD.stroke_width(3)));
    chart.draw_series(rows.iter().map(|row| {
        Cross::new(
            (row.mirror_weight, row.binding_strength_mean),
            7,
            PAL_CD.mix(0.90).stroke_width(2),
        )
    }))?;

    chart
        .configure_series_labels()
        .border_style(BLACK.mix(0.4))
        .background_style(WHITE.mix(0.8))
        .draw()?;

    root.present()?;
    Ok(())
}

#[allow(dead_code)]
fn render_e4_fingerprint_heatmap_png(
    out_path: &Path,
    summary_rows: &[E4FingerprintSummaryRow],
) -> Result<(), Box<dyn Error>> {
    if summary_rows.is_empty() {
        return Ok(());
    }
    let mut weight_keys: Vec<i32> = summary_rows
        .iter()
        .map(|row| float_key(row.mirror_weight))
        .collect();
    weight_keys.sort();
    weight_keys.dedup();
    if weight_keys.is_empty() {
        return Ok(());
    }
    let weights: Vec<f32> = weight_keys.iter().map(|key| float_from_key(*key)).collect();

    let mut mean_map: std::collections::HashMap<(i32, &'static str), f32> =
        std::collections::HashMap::new();
    let mut max_prob = 0.0f32;
    for row in summary_rows {
        mean_map.insert((float_key(row.mirror_weight), row.category), row.mean_prob);
        max_prob = max_prob.max(row.mean_prob);
    }
    let labels = E4_FINGERPRINT_LABELS;

    log_output_path(out_path);
    let root = BitMapBackend::new(out_path, (1500, 900)).into_drawing_area();
    root.fill(&WHITE)?;
    let mut chart = ChartBuilder::on(&root)
        .caption(
            "E4 Interval Fingerprint Heatmap (JI categories)",
            ("sans-serif", 24),
        )
        .margin(14)
        .x_label_area_size(46)
        .y_label_area_size(90)
        .build_cartesian_2d(0i32..weights.len() as i32, 0i32..labels.len() as i32)?;

    chart
        .configure_mesh()
        .disable_mesh()
        .x_desc("mirror_weight")
        .y_desc("interval category")
        .x_labels(weights.len())
        .y_labels(labels.len())
        .x_label_formatter(&|x| {
            let idx = (*x).clamp(0, weights.len().saturating_sub(1) as i32) as usize;
            format!("{:.2}", weights[idx])
        })
        .y_label_formatter(&|y| {
            let idx = (*y).clamp(0, labels.len().saturating_sub(1) as i32) as usize;
            labels[idx].to_string()
        })
        .draw()?;

    for (x_idx, weight_key) in weight_keys.iter().enumerate() {
        for (y_idx, category) in labels.iter().enumerate() {
            let prob = mean_map
                .get(&(*weight_key, *category))
                .copied()
                .unwrap_or(0.0)
                .clamp(0.0, 1.0);
            let t = if max_prob > 1e-9 {
                (prob / max_prob).clamp(0.0, 1.0)
            } else {
                0.0
            };
            let color = RGBColor(
                (255.0 * t) as u8,
                (30.0 + 170.0 * (1.0 - t)) as u8,
                (255.0 * (1.0 - t)) as u8,
            );
            chart.draw_series(std::iter::once(Rectangle::new(
                [
                    (x_idx as i32, y_idx as i32),
                    ((x_idx + 1) as i32, (y_idx + 1) as i32),
                ],
                color.filled(),
            )))?;
        }
    }

    root.present()?;
    Ok(())
}

#[allow(dead_code)]
fn render_e4_figure2_interval_hist_triptych(
    out_path: &Path,
    hist_records: &[E4HistRecord],
    bin_width: f32,
) -> Result<(), Box<dyn Error>> {
    let targets = [0.0f32, 0.5f32, 1.0f32];
    let mut panels: Vec<(f32, Histogram)> = Vec::new();
    for &w in &targets {
        if let Some(hist) = mean_histogram_for_weight(hist_records, w, bin_width) {
            panels.push((w, hist));
        }
    }
    if panels.is_empty() {
        return Ok(());
    }
    let bin_width_cents = (bin_width * 100.0).max(1.0);
    let mut y_max = 0.0f32;
    for (_, hist) in &panels {
        y_max = y_max.max(hist.masses.iter().copied().fold(0.0f32, f32::max));
    }
    y_max = (y_max * 1.2).max(1e-4);

    let root = bitmap_root(out_path, (1500, 520)).into_drawing_area();
    root.fill(&WHITE)?;
    let areas = root.split_evenly((1, panels.len()));
    for (i, area) in areas.iter().enumerate() {
        let (weight, hist) = &panels[i];
        let mut chart = ChartBuilder::on(area)
            .caption(
                format!("E4 Figure 2: w={weight:.2} (bin={bin_width_cents:.1}c)"),
                ("sans-serif", 16),
            )
            .margin(10)
            .x_label_area_size(40)
            .y_label_area_size(52)
            .build_cartesian_2d(0.0f32..1200.0f32, 0.0f32..y_max)?;
        chart
            .configure_mesh()
            .x_desc("interval cents (pitch class)")
            .y_desc("probability density (sum=1)")
            .x_labels(7)
            .draw()?;
        for &x in &[E4_CENTS_MIN3, E4_CENTS_MAJ3, E4_CENTS_P4, E4_CENTS_P5] {
            chart.draw_series(std::iter::once(PathElement::new(
                vec![(x, 0.0), (x, y_max)],
                BLACK.mix(0.2),
            )))?;
        }
        chart.draw_series(
            hist.bin_centers
                .iter()
                .zip(hist.masses.iter())
                .map(|(x, y)| {
                    let x0 = (*x - 0.5 * bin_width_cents).max(0.0);
                    let x1 = (*x + 0.5 * bin_width_cents).min(1200.0);
                    Rectangle::new([(x0, 0.0), (x1, *y)], PAL_H.mix(0.55).filled())
                }),
        )?;
    }
    root.present()?;
    Ok(())
}

fn delta_t_from_freqs(anchor_hz: f32, freqs: &[f32], eps_cents: f32, mode: E4CountMode) -> f32 {
    let masses = interval_masses_from_freqs(anchor_hz, freqs, eps_cents, mode);
    let (_, _, delta_t, _) = triad_scores(masses);
    delta_t
}

fn render_e4_step_response_delta_plot(
    out_path: &Path,
    step_rows: &[(u32, f32, f32, f32)],
    switch_step: u32,
) -> Result<(), Box<dyn Error>> {
    if step_rows.is_empty() {
        return Ok(());
    }
    let mut y_min = f32::INFINITY;
    let mut y_max = f32::NEG_INFINITY;
    for (_, _, d_soft, d_hard) in step_rows {
        y_min = y_min.min(*d_soft).min(*d_hard).min(0.0);
        y_max = y_max.max(*d_soft).max(*d_hard).max(0.0);
    }
    if !y_min.is_finite() || !y_max.is_finite() || (y_max - y_min).abs() < 1e-6 {
        y_min = -0.1;
        y_max = 0.1;
    }
    let pad = 0.12 * (y_max - y_min);
    let x_end = step_rows
        .last()
        .map(|(s, _, _, _)| *s as f32)
        .unwrap_or(1.0f32);

    let root = bitmap_root(out_path, (1300, 700)).into_drawing_area();
    root.fill(&WHITE)?;
    let mut chart = ChartBuilder::on(&root)
        .caption("E4 Step Response: ΔT(t)", ("sans-serif", 20))
        .margin(10)
        .x_label_area_size(42)
        .y_label_area_size(60)
        .build_cartesian_2d(0.0f32..x_end.max(1.0), (y_min - pad)..(y_max + pad))?;
    chart.configure_mesh().x_desc("step").y_desc("ΔT").draw()?;
    chart.draw_series(std::iter::once(PathElement::new(
        vec![(0.0, 0.0), (x_end.max(1.0), 0.0)],
        BLACK.mix(0.8).stroke_width(3),
    )))?;
    chart.draw_series(std::iter::once(PathElement::new(
        vec![
            (switch_step as f32, y_min - pad),
            (switch_step as f32, y_max + pad),
        ],
        BLACK.mix(0.45).stroke_width(2),
    )))?;
    chart.draw_series(std::iter::once(Text::new(
        "phase switch",
        (
            (switch_step as f32 + 5.0).min(x_end * 0.95),
            y_max + 0.03 * (y_max - y_min + 1e-6),
        ),
        ("sans-serif", 14).into_font().color(&BLACK.mix(0.7)),
    )))?;
    chart.draw_series(LineSeries::new(
        step_rows
            .iter()
            .map(|(step, _, delta_soft, _)| (*step as f32, *delta_soft)),
        PAL_H.mix(0.9).stroke_width(2),
    ))?;
    chart.draw_series(LineSeries::new(
        step_rows
            .iter()
            .map(|(step, _, _, delta_hard)| (*step as f32, *delta_hard)),
        PAL_R.mix(0.75).stroke_width(2),
    ))?;
    root.present()?;
    Ok(())
}

