    #[test]
    fn oracle_chord_delta_is_stable_under_noop_update() {
        let meta = e4_paper_meta();
        let space = Log2Space::new(meta.fmin, meta.fmax, meta.bins_per_oct);
        let (erb_scan, du_scan) = erb_grid(&space);
        let freqs = [
            meta.anchor_hz,
            meta.anchor_hz * (5.0 / 4.0),
            meta.anchor_hz * (3.0 / 2.0),
            meta.anchor_hz * 2.0,
        ];
        let scan = compute_e4_landscape_scans(&space, meta.anchor_hz, 1.0, 0.0, &freqs, &du_scan);
        let mut indices: Vec<usize> = freqs.iter().map(|f| space.nearest_index(*f)).collect();
        let kernel_params = KernelParams::default();
        let before =
            bind_eval_from_indices(meta.anchor_hz, &scan.log2_ratio, &indices).harmonic_tilt;
        e4_wr_probe_update_indices(
            &mut indices,
            &scan.c,
            &erb_scan,
            0,
            scan.c.len().saturating_sub(1),
            0,
            0.0,
            &kernel_params,
            None,
            true,
        );
        let after =
            bind_eval_from_indices(meta.anchor_hz, &scan.log2_ratio, &indices).harmonic_tilt;
        assert!(
            (before - after).abs() < 1e-6,
            "noop update should keep harmonic_tilt (before={before}, after={after})"
        );
    }

